const detectionEngineeringDefenseHtml = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>DETECT//04 — Detection Engineering & Defense</title>\n<style>\n@import url('https://fonts.googleapis.com/css2?family=Martian+Mono:wght@300;400;600;700;800&family=Unbounded:wght@300;700;900&family=Instrument+Sans:ital,wght@0,300;0,400;0,600;1,300&display=swap');\n\n:root {\n  --void:   #080a08;\n  --deep:   #0d110d;\n  --panel:  #111811;\n  --surface:#162016;\n  --lift:   #1c281c;\n\n  --amber:  #ffb700;\n  --amber2: #e09900;\n  --amber3: #c07800;\n  --lime:   #7dff4f;\n  --lime2:  #5acc30;\n  --red:    #ff3322;\n  --red2:   #cc1100;\n  --cyan:   #22ddff;\n  --cyan2:  #00aabb;\n  --white:  #e8f0e8;\n  --dim:    #3a503a;\n  --muted:  #1e2e1e;\n  --rule:   #192419;\n\n  --mono: 'Martian Mono', monospace;\n  --display: 'Unbounded', sans-serif;\n  --body: 'Instrument Sans', sans-serif;\n}\n\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\nhtml { scroll-behavior: smooth; }\n\nbody {\n  background: var(--void);\n  color: var(--white);\n  font-family: var(--body);\n  min-height: 100vh;\n  overflow-x: hidden;\n  cursor: crosshair;\n}\n\n/* ── CIRCUIT BOARD BACKGROUND ── */\nbody::before {\n  content: '';\n  position: fixed; inset: 0;\n  background-image:\n    linear-gradient(rgba(255,183,0,.03) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(255,183,0,.03) 1px, transparent 1px),\n    linear-gradient(rgba(255,183,0,.015) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(255,183,0,.015) 1px, transparent 1px);\n  background-size: 80px 80px, 80px 80px, 16px 16px, 16px 16px;\n  pointer-events: none; z-index: 0;\n}\n\n/* Amber glow at top */\nbody::after {\n  content: '';\n  position: fixed; top: 0; left: 0; right: 0; height: 300px;\n  background: radial-gradient(ellipse 800px 300px at 50% 0%, rgba(255,183,0,.07) 0%, transparent 70%);\n  pointer-events: none; z-index: 0;\n}\n\n.z1 { position: relative; z-index: 1; }\n\n/* ── NAV ── */\nnav {\n  position: sticky; top: 0; z-index: 200;\n  height: 52px;\n  display: flex; align-items: stretch;\n  background: rgba(8,10,8,.95);\n  backdrop-filter: blur(20px);\n  border-bottom: 1px solid rgba(255,183,0,.15);\n  overflow-x: auto; scrollbar-width: none;\n}\nnav::-webkit-scrollbar { display: none; }\n\n.nav-logo {\n  display: flex; align-items: center;\n  padding: 0 20px;\n  border-right: 1px solid var(--rule);\n  flex-shrink: 0;\n  gap: 10px;\n}\n.nav-logo-mark {\n  width: 28px; height: 28px;\n  background: var(--amber);\n  clip-path: polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%);\n  display: flex; align-items: center; justify-content: center;\n  flex-shrink: 0;\n}\n.nav-logo-mark::after {\n  content: '04';\n  font-family: var(--mono);\n  font-size: .45rem;\n  font-weight: 800;\n  color: var(--void);\n  letter-spacing: 1px;\n}\n.nav-logo-text {\n  font-family: var(--display);\n  font-size: .65rem;\n  font-weight: 700;\n  letter-spacing: 3px;\n  color: var(--amber);\n}\n\n.ntabs { display: flex; }\n.ntab {\n  font-family: var(--mono);\n  font-size: .55rem;\n  font-weight: 600;\n  letter-spacing: 1.5px;\n  text-transform: uppercase;\n  padding: 0 16px;\n  cursor: pointer;\n  color: var(--dim);\n  background: none; border: none;\n  border-right: 1px solid var(--rule);\n  white-space: nowrap;\n  transition: all .2s;\n}\n.ntab:hover { color: var(--amber); background: rgba(255,183,0,.04); }\n.ntab.active { color: var(--void); background: var(--amber); }\n\n/* ── HERO ── */\n.hero {\n  padding: 0 0 0;\n  position: relative;\n  overflow: hidden;\n  border-bottom: 1px solid rgba(255,183,0,.12);\n  min-height: 220px;\n  display: flex; align-items: stretch;\n}\n\n.hero-left {\n  flex: 1;\n  padding: 52px 48px;\n  border-right: 1px solid rgba(255,183,0,.1);\n}\n\n.hero-eyebrow {\n  font-family: var(--mono);\n  font-size: .55rem;\n  letter-spacing: 5px;\n  color: rgba(255,183,0,.5);\n  margin-bottom: 16px;\n  display: flex; align-items: center; gap: 10px;\n}\n.hero-eyebrow::before {\n  content: '';\n  display: block; width: 40px; height: 1px;\n  background: rgba(255,183,0,.3);\n}\n\n.hero-h1 {\n  font-family: var(--display);\n  font-size: clamp(2.4rem, 6vw, 4.8rem);\n  font-weight: 900;\n  line-height: .9;\n  letter-spacing: -2px;\n  margin-bottom: 20px;\n}\n.hero-h1 .hl { color: var(--amber); }\n.hero-h1 .dim { color: var(--dim); }\n\n.hero-desc {\n  font-size: .95rem;\n  color: var(--dim);\n  font-weight: 300;\n  line-height: 1.75;\n  max-width: 500px;\n  margin-bottom: 24px;\n}\n\n.hero-tags { display: flex; flex-wrap: wrap; gap: 6px; }\n.htag {\n  font-family: var(--mono);\n  font-size: .52rem;\n  letter-spacing: 2px;\n  padding: 4px 10px;\n  border: 1px solid rgba(255,183,0,.2);\n  color: rgba(255,183,0,.6);\n  border-radius: 1px;\n  text-transform: uppercase;\n}\n\n.hero-right {\n  width: 300px;\n  flex-shrink: 0;\n  display: flex; flex-direction: column;\n  border-left: 1px solid rgba(255,183,0,.08);\n}\n.hero-stat {\n  flex: 1;\n  padding: 20px 24px;\n  border-bottom: 1px solid var(--rule);\n  display: flex; flex-direction: column; justify-content: center;\n}\n.hero-stat:last-child { border-bottom: none; }\n.stat-label { font-family: var(--mono); font-size: .52rem; letter-spacing: 3px; color: var(--dim); margin-bottom: 6px; text-transform: uppercase; }\n.stat-val { font-family: var(--display); font-size: 1.6rem; font-weight: 900; color: var(--amber); letter-spacing: -1px; }\n.stat-sub { font-size: .75rem; color: var(--dim); font-weight: 300; margin-top: 2px; }\n\n@media(max-width:768px) { .hero-right { display: none; } .hero-left { padding: 36px 20px; } }\n\n/* ── MODULE / WRAPPER ── */\n.module { display: none; }\n.module.active { display: block; }\n.wrapper { max-width: 1200px; margin: 0 auto; padding: 44px 48px 80px; }\n@media(max-width:640px) { .wrapper { padding: 24px 16px 60px; } }\n\n/* ── SECTION HEADER ── */\n.sh {\n  margin-bottom: 32px;\n  padding-bottom: 20px;\n  border-bottom: 1px solid var(--rule);\n  display: flex; gap: 0; align-items: stretch;\n}\n.sh-accent {\n  width: 4px;\n  background: var(--amber);\n  margin-right: 20px;\n  flex-shrink: 0;\n  border-radius: 2px;\n}\n.sh-body {}\n.sh-eyebrow { font-family: var(--mono); font-size: .52rem; letter-spacing: 4px; color: var(--dim); margin-bottom: 8px; text-transform: uppercase; }\n.sh-title { font-family: var(--display); font-size: 1.8rem; font-weight: 900; letter-spacing: -1px; line-height: 1; margin-bottom: 8px; }\n.sh-desc { font-size: .92rem; color: var(--dim); font-weight: 300; line-height: 1.65; max-width: 680px; }\n\n/* ── GRIDS ── */\n.g2 { display: grid; grid-template-columns: repeat(2,1fr); gap: 12px; }\n.g3 { display: grid; grid-template-columns: repeat(3,1fr); gap: 12px; }\n.g4 { display: grid; grid-template-columns: repeat(4,1fr); gap: 10px; }\n.gasym { display: grid; grid-template-columns: 1.6fr 1fr; gap: 12px; }\n@media(max-width:860px) { .g2,.g3,.g4,.gasym { grid-template-columns: 1fr; } }\n\n/* ── CARDS ── */\n.card {\n  background: var(--panel);\n  border: 1px solid var(--rule);\n  border-radius: 2px;\n  padding: 20px;\n  position: relative;\n  overflow: hidden;\n  transition: border-color .25s, background .25s;\n}\n.card:hover { border-color: rgba(255,183,0,.2); background: var(--surface); }\n\n/* accent strip top */\n.card::before {\n  content: '';\n  position: absolute; top: 0; left: 0; right: 0; height: 1px;\n  background: var(--card-top, transparent);\n  transition: background .3s;\n}\n.card:hover::before { background: var(--card-hover, transparent); }\n\n.ca { --card-hover: rgba(255,183,0,.4); }\n.cl { --card-hover: rgba(125,255,79,.4); }\n.cr { --card-hover: rgba(255,51,34,.4); }\n.cc { --card-hover: rgba(34,221,255,.4); }\n\n.clabel { font-family: var(--mono); font-size: .52rem; letter-spacing: 3px; color: var(--dim); margin-bottom: 8px; text-transform: uppercase; }\n.ctitle { font-family: var(--display); font-size: 1rem; font-weight: 700; letter-spacing: -.5px; margin-bottom: 10px; line-height: 1.1; }\n.cbody { font-size: .85rem; color: var(--dim); line-height: 1.7; font-weight: 300; }\n.cbody strong { color: var(--white); font-weight: 600; }\n.cbody code { font-family: var(--mono); font-size: .72rem; color: var(--lime); background: rgba(125,255,79,.07); padding: 1px 5px; border-radius: 1px; }\n\n/* ── CODE BLOCKS ── */\n.codeblock {\n  background: #030503;\n  border: 1px solid rgba(255,183,0,.08);\n  border-left: 2px solid var(--cb-accent, rgba(255,183,0,.3));\n  border-radius: 2px;\n  padding: 16px 18px;\n  font-family: var(--mono);\n  font-size: .68rem;\n  font-weight: 400;\n  line-height: 1.95;\n  overflow-x: auto;\n  margin: 10px 0;\n  color: #3a5a3a;\n  position: relative;\n}\n.codeblock .lb { position: absolute; top: 6px; right: 10px; font-size: .5rem; letter-spacing: 2px; color: rgba(255,183,0,.25); text-transform: uppercase; }\n.K  { color: #ffb700; font-weight: 600; }  /* keyword */\n.F  { color: #7dff4f; }                     /* function/cmd */\n.S  { color: #ffdd88; }                     /* string */\n.N  { color: #ff8844; }                     /* number */\n.C  { color: #1e3020; font-style: italic; } /* comment */\n.V  { color: #88cc88; }                     /* variable */\n.H  { color: #aaddaa; }                     /* highlighted text */\n.R  { color: #ff3322; }                     /* red/danger */\n.G  { color: #7dff4f; }                     /* green/good */\n.Y  { color: #ffb700; }                     /* yellow/warn */\n.CY { color: #22ddff; }                     /* cyan */\n.W  { color: #e8f0e8; }                     /* white */\n.P  { color: #cc88ff; }                     /* purple */\n\n/* ── RULE BLOCKS ── */\n.rule-block {\n  background: #030503;\n  border: 1px solid rgba(255,183,0,.12);\n  border-radius: 2px;\n  overflow: hidden;\n  margin: 12px 0;\n}\n.rule-header {\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 8px 14px;\n  background: rgba(255,183,0,.06);\n  border-bottom: 1px solid rgba(255,183,0,.1);\n}\n.rule-name { font-family: var(--mono); font-size: .6rem; letter-spacing: 2px; color: var(--amber); font-weight: 600; text-transform: uppercase; }\n.rule-sev {\n  font-family: var(--mono); font-size: .52rem; letter-spacing: 1px;\n  padding: 2px 8px; border-radius: 1px;\n}\n.sev-crit { background: rgba(255,51,34,.2); color: var(--red); border: 1px solid rgba(255,51,34,.3); }\n.sev-high { background: rgba(255,183,0,.15); color: var(--amber); border: 1px solid rgba(255,183,0,.3); }\n.sev-med  { background: rgba(125,255,79,.1); color: var(--lime2); border: 1px solid rgba(125,255,79,.25); }\n.rule-body { padding: 14px 18px; font-family: var(--mono); font-size: .68rem; line-height: 1.95; color: #3a5a3a; overflow-x: auto; }\n\n/* ── ALERT ── */\n.alert { border-radius: 2px; padding: 12px 16px; margin: 12px 0; font-size: .85rem; line-height: 1.65; font-weight: 300; border-left: 2px solid; }\n.alert strong { font-weight: 600; }\n.a-warn { background: rgba(255,183,0,.06); border-color: var(--amber); color: rgba(255,183,0,.8); }\n.a-info { background: rgba(34,221,255,.05); border-color: var(--cyan2); color: var(--cyan2); }\n.a-ok   { background: rgba(125,255,79,.05); border-color: var(--lime2); color: var(--lime2); }\n.a-err  { background: rgba(255,51,34,.06);  border-color: var(--red2); color: var(--red); }\n\n/* ── TABLE ── */\n.dTable { width: 100%; border-collapse: collapse; margin: 10px 0; font-size: .82rem; }\n.dTable th { font-family: var(--mono); font-size: .52rem; letter-spacing: 2px; text-transform: uppercase; padding: 9px 14px; text-align: left; background: var(--surface); color: var(--amber); border: 1px solid var(--rule); }\n.dTable td { padding: 9px 14px; border: 1px solid var(--rule); vertical-align: top; line-height: 1.5; color: var(--dim); font-weight: 300; }\n.dTable tr:hover td { background: var(--surface); color: var(--white); }\n.dTable td strong { color: var(--white); font-weight: 500; }\n.dTable td code { font-family: var(--mono); font-size: .7rem; color: var(--lime); }\n.tc-r { color: var(--red); font-family: var(--mono); font-size: .7rem; font-weight: 700; }\n.tc-y { color: var(--amber); font-family: var(--mono); font-size: .7rem; font-weight: 700; }\n.tc-g { color: var(--lime2); font-family: var(--mono); font-size: .7rem; font-weight: 700; }\n.tc-c { color: var(--cyan2); font-family: var(--mono); font-size: .7rem; font-weight: 700; }\n\n/* ── DIVIDER ── */\n.divline { height: 1px; background: var(--rule); margin: 28px 0; }\n\n/* ── BADGE ROW ── */\n.badges { display: flex; flex-wrap: wrap; gap: 5px; margin-top: 10px; }\n.badge { font-family: var(--mono); font-size: .52rem; letter-spacing: 1px; padding: 2px 8px; border-radius: 1px; border: 1px solid; text-transform: uppercase; }\n.ba { color: var(--amber); border-color: rgba(255,183,0,.3); background: rgba(255,183,0,.05); }\n.bl { color: var(--lime2); border-color: rgba(125,255,79,.3); background: rgba(125,255,79,.05); }\n.br { color: var(--red); border-color: rgba(255,51,34,.3); background: rgba(255,51,34,.05); }\n.bc { color: var(--cyan2); border-color: rgba(34,221,255,.3); background: rgba(34,221,255,.05); }\n\n/* ── IN-PAGE TABS ── */\n.itabs { display: flex; border-bottom: 1px solid var(--rule); margin-bottom: 0; overflow-x: auto; scrollbar-width: none; }\n.itabs::-webkit-scrollbar { display: none; }\n.itab { font-family: var(--mono); font-size: .55rem; letter-spacing: 2px; text-transform: uppercase; padding: 10px 16px; cursor: pointer; color: var(--dim); background: none; border: none; border-bottom: 2px solid transparent; margin-bottom: -1px; white-space: nowrap; transition: all .18s; }\n.itab:hover { color: var(--amber); }\n.itab.active { color: var(--amber); border-bottom-color: var(--amber); }\n.ipanel { display: none; padding-top: 20px; }\n.ipanel.active { display: block; }\n\n/* ── HUNT PIPELINE ── */\n.hunt-pipe {\n  display: flex; gap: 0;\n  border: 1px solid var(--rule);\n  border-radius: 2px;\n  overflow: hidden;\n  margin: 14px 0;\n}\n.hp-step {\n  flex: 1; min-width: 110px;\n  padding: 16px 12px;\n  text-align: center;\n  border-right: 1px solid var(--rule);\n  background: var(--panel);\n  transition: background .2s;\n  position: relative;\n}\n.hp-step:last-child { border-right: none; }\n.hp-step:hover { background: var(--surface); }\n.hp-step::after { content: '▶'; position: absolute; right: -8px; top: 50%; transform: translateY(-50%); color: var(--dim); font-size: .7rem; z-index: 2; }\n.hp-step:last-child::after { display: none; }\n.hp-n { font-family: var(--mono); font-size: .48rem; letter-spacing: 2px; color: var(--muted); margin-bottom: 6px; }\n.hp-icon { font-size: 1.3rem; margin-bottom: 5px; }\n.hp-name { font-family: var(--mono); font-size: .6rem; letter-spacing: 1px; color: var(--amber); margin-bottom: 3px; font-weight: 600; text-transform: uppercase; }\n.hp-desc { font-size: .7rem; color: var(--dim); line-height: 1.3; }\n\n/* ── DETECTION PYRAMID ── */\n.pyramid {\n  display: flex; flex-direction: column; gap: 3px;\n  margin: 16px 0;\n}\n.pyr-row {\n  display: flex; align-items: center; gap: 12px;\n  padding: 10px 16px;\n  border-radius: 2px;\n  border: 1px solid;\n  transition: all .2s;\n  cursor: default;\n}\n.pyr-row:hover { transform: translateX(4px); }\n.pr-1 { background: rgba(255,51,34,.08);  border-color: rgba(255,51,34,.2);  }\n.pr-2 { background: rgba(255,183,0,.06);  border-color: rgba(255,183,0,.2);  margin: 0 20px; }\n.pr-3 { background: rgba(125,255,79,.05); border-color: rgba(125,255,79,.18); margin: 0 40px; }\n.pr-4 { background: rgba(34,221,255,.04); border-color: rgba(34,221,255,.15); margin: 0 60px; }\n.pyr-label { font-family: var(--mono); font-size: .62rem; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; min-width: 130px; }\n.pr-1 .pyr-label { color: var(--red); }\n.pr-2 .pyr-label { color: var(--amber); }\n.pr-3 .pyr-label { color: var(--lime2); }\n.pr-4 .pyr-label { color: var(--cyan2); }\n.pyr-desc { font-size: .82rem; color: var(--dim); font-weight: 300; }\n.pyr-diff { font-family: var(--mono); font-size: .55rem; color: var(--dim); margin-left: auto; flex-shrink: 0; }\n\n/* ── SIGMA BLOCK ── */\n.sigma-block {\n  background: #030503;\n  border: 1px solid rgba(34,221,255,.12);\n  border-radius: 2px;\n  overflow: hidden;\n  margin: 12px 0;\n}\n.sigma-hdr {\n  display: flex; align-items: center; gap: 10px;\n  padding: 8px 14px;\n  background: rgba(34,221,255,.06);\n  border-bottom: 1px solid rgba(34,221,255,.1);\n}\n.sigma-tag { width: 8px; height: 8px; background: var(--cyan2); border-radius: 50%; flex-shrink: 0; }\n.sigma-title { font-family: var(--mono); font-size: .6rem; letter-spacing: 2px; color: var(--cyan2); font-weight: 600; }\n.sigma-body { padding: 14px 18px; font-family: var(--mono); font-size: .68rem; line-height: 1.95; color: #3a5a3a; overflow-x: auto; }\n\n/* ── QUIZ ── */\n.quiz-card {\n  background: var(--panel);\n  border: 1px solid var(--rule);\n  border-radius: 2px;\n  padding: 22px;\n  margin-bottom: 12px;\n}\n.qnum { font-family: var(--mono); font-size: .52rem; letter-spacing: 3px; color: var(--dim); margin-bottom: 8px; text-transform: uppercase; }\n.qtext { font-size: .95rem; font-weight: 400; color: var(--white); margin-bottom: 16px; line-height: 1.55; }\n.qopts { display: flex; flex-direction: column; gap: 6px; }\n.qopt {\n  font-family: var(--mono); font-size: .7rem;\n  padding: 10px 14px; border: 1px solid var(--rule); border-radius: 1px;\n  background: var(--surface); color: var(--dim); text-align: left; cursor: pointer;\n  transition: all .18s; line-height: 1.45;\n}\n.qopt:hover:not(.locked) { border-color: rgba(255,183,0,.3); color: var(--amber); background: var(--lift); }\n.qopt.correct { border-color: var(--lime2); background: rgba(125,255,79,.08); color: var(--lime2); }\n.qopt.wrong   { border-color: var(--red2); background: rgba(255,51,34,.06); color: var(--red); }\n.qexplain { margin-top: 12px; padding: 12px 16px; background: var(--deep); border-left: 2px solid var(--amber); border-radius: 2px; font-size: .83rem; color: var(--dim); line-height: 1.65; display: none; font-weight: 300; }\n.qexplain.show { display: block; }\n.qexplain strong { color: var(--amber); }\n.qexplain code { font-family: var(--mono); font-size: .7rem; color: var(--lime); }\n\n/* score */\n.score-box { background: var(--panel); border: 1px solid var(--rule); border-radius: 2px; padding: 20px; margin-top: 20px; }\n.score-track { height: 4px; background: var(--rule); border-radius: 2px; margin: 10px 0; overflow: hidden; }\n.score-fill { height: 100%; border-radius: 2px; transition: width .5s, background .5s; }\n.reset-btn { font-family: var(--mono); font-size: .58rem; letter-spacing: 2px; text-transform: uppercase; padding: 8px 18px; background: none; color: var(--amber); border: 1px solid rgba(255,183,0,.3); border-radius: 1px; cursor: pointer; transition: all .2s; margin-top: 10px; }\n.reset-btn:hover { background: rgba(255,183,0,.08); }\n</style>\n</head>\n<body>\n\n<!-- ══ NAV ══ -->\n<nav class=\"z1\">\n  <div class=\"nav-logo\">\n    <div class=\"nav-logo-mark\"></div>\n    <div class=\"nav-logo-text\">DETECT//04</div>\n  </div>\n  <div class=\"ntabs\">\n    <button class=\"ntab active\" onclick=\"sw('overview',this)\">Overview</button>\n    <button class=\"ntab\" onclick=\"sw('edr',this)\">EDR Logic</button>\n    <button class=\"ntab\" onclick=\"sw('sigma',this)\">Sigma Rules</button>\n    <button class=\"ntab\" onclick=\"sw('siem',this)\">SIEM Queries</button>\n    <button class=\"ntab\" onclick=\"sw('hunting',this)\">Threat Hunting</button>\n    <button class=\"ntab\" onclick=\"sw('forensics',this)\">Forensics</button>\n    <button class=\"ntab\" onclick=\"sw('playbooks',this)\">IR Playbooks</button>\n    <button class=\"ntab\" onclick=\"sw('quiz',this)\">Check</button>\n  </div>\n</nav>\n\n<!-- ══ HERO ══ -->\n<div class=\"hero z1\">\n  <div class=\"hero-left\">\n    <div class=\"hero-eyebrow\">Module 04 — Detection Engineering & Defense</div>\n    <h1 class=\"hero-h1\">\n      <span class=\"hl\">DETECT</span><br>\n      <span class=\"dim\">HUNT</span><br>\n      <span class=\"hl\">RESPOND</span>\n    </h1>\n    <p class=\"hero-desc\">Signature-based vs behavioral detection. EDR hook chains. Writing Sigma rules and KQL/SPL queries. Structured threat hunting. Digital forensics and IR playbooks — the complete blue team engineering stack.</p>\n    <div class=\"hero-tags\">\n      <span class=\"htag\">EDR Logic</span>\n      <span class=\"htag\">Sigma / YARA</span>\n      <span class=\"htag\">KQL / SPL</span>\n      <span class=\"htag\">Threat Hunting</span>\n      <span class=\"htag\">DFIR</span>\n      <span class=\"htag\">IR Playbooks</span>\n    </div>\n  </div>\n  <div class=\"hero-right\">\n    <div class=\"hero-stat\">\n      <div class=\"stat-label\">Primary Role</div>\n      <div class=\"stat-val\">BLUE TEAM</div>\n      <div class=\"stat-sub\">Detection Engineering</div>\n    </div>\n    <div class=\"hero-stat\">\n      <div class=\"stat-label\">Frameworks</div>\n      <div class=\"stat-val\">ATT&CK</div>\n      <div class=\"stat-sub\">D3FEND · NIST CSF</div>\n    </div>\n    <div class=\"hero-stat\">\n      <div class=\"stat-label\">Rule Formats</div>\n      <div class=\"stat-val\">3</div>\n      <div class=\"stat-sub\">YARA · Sigma · KQL/SPL</div>\n    </div>\n  </div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: OVERVIEW\n══════════════════════════════════ -->\n<div class=\"module active z1\" id=\"mod-overview\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.0 — The Detection Landscape //</div>\n      <div class=\"sh-title\">Detection Methodology</div>\n      <div class=\"sh-desc\">Detection engineering is the systematic process of converting threat knowledge into reliable, low-false-positive detections. It sits at the intersection of threat intelligence, data engineering, and security operations.</div>\n    </div>\n  </div>\n\n  <!-- Pyramid of Pain -->\n  <div class=\"card ca\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">David Bianco's Model — 2013</div>\n    <div class=\"ctitle\" style=\"color:var(--amber)\">PYRAMID OF PAIN</div>\n    <div class=\"cbody\" style=\"margin-bottom:14px\">How painful is it for the attacker if you detect and block this indicator? Hash blocks are trivial to defeat — TTPs require fundamental retooling.</div>\n    <div class=\"pyramid\">\n      <div class=\"pyr-row pr-1\">\n        <span class=\"pyr-label\">TTPs</span>\n        <span class=\"pyr-desc\">Behavioral patterns — how adversaries operate. Hardest to change. Detection here forces fundamental retooling.</span>\n        <span class=\"pyr-diff\">TOUGH for attacker</span>\n      </div>\n      <div class=\"pyr-row pr-2\">\n        <span class=\"pyr-label\">TOOLS</span>\n        <span class=\"pyr-desc\">Specific malware families, C2 frameworks (Cobalt Strike, Sliver). Attacker must find/build alternatives.</span>\n        <span class=\"pyr-diff\">CHALLENGING</span>\n      </div>\n      <div class=\"pyr-row pr-3\">\n        <span class=\"pyr-label\">NETWORK IOCs</span>\n        <span class=\"pyr-desc\">C2 domains, IP addresses, URLs. Moderate cost to rotate infrastructure.</span>\n        <span class=\"pyr-diff\">ANNOYING</span>\n      </div>\n      <div class=\"pyr-row pr-4\">\n        <span class=\"pyr-label\">HASHES / IPs</span>\n        <span class=\"pyr-desc\">File hashes (MD5/SHA256), attacker IPs. Trivial to change — recompile or spin new VPS.</span>\n        <span class=\"pyr-diff\">TRIVIAL for attacker</span>\n      </div>\n    </div>\n    <div class=\"alert a-ok\" style=\"margin-top:8px\"><strong>Engineering principle:</strong> Invest heavily in TTP-level detections (behavioral). Hash and IP blocklists are necessary hygiene but insufficient defenses — attackers change them in minutes.</div>\n  </div>\n\n  <!-- Detection types overview -->\n  <div class=\"g3\" style=\"margin-bottom:14px\">\n    <div class=\"card ca\">\n      <div class=\"clabel\">Detection Method 01</div>\n      <div class=\"ctitle\" style=\"color:var(--amber)\">Signature-Based</div>\n      <div class=\"cbody\">\n        <p style=\"margin-bottom:10px\">Matches known-bad patterns: file hashes, byte sequences, domain names. Fast, cheap, high-fidelity for <strong>known threats</strong>.</p>\n        <strong style=\"font-size:.8rem\">Strengths:</strong>\n        <ul style=\"margin:6px 0 0 14px;font-size:.8rem;line-height:1.8;color:var(--dim)\">\n          <li>Zero false positives on exact match</li>\n          <li>Extremely fast execution</li>\n          <li>Easy to share (IOC feeds)</li>\n        </ul>\n        <strong style=\"font-size:.8rem\">Weaknesses:</strong>\n        <ul style=\"margin:6px 0 0 14px;font-size:.8rem;line-height:1.8;color:var(--dim)\">\n          <li>Blind to new/modified variants</li>\n          <li>1-bit change defeats hash match</li>\n          <li>Requires constant updates</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"card cl\">\n      <div class=\"clabel\">Detection Method 02</div>\n      <div class=\"ctitle\" style=\"color:var(--lime2)\">Behavioral / Heuristic</div>\n      <div class=\"cbody\">\n        <p style=\"margin-bottom:10px\">Detects anomalous <strong>actions and sequences</strong>, not specific signatures. Catches zero-days and novel variants. The direction modern EDR is heading.</p>\n        <strong style=\"font-size:.8rem\">Strengths:</strong>\n        <ul style=\"margin:6px 0 0 14px;font-size:.8rem;line-height:1.8;color:var(--dim)\">\n          <li>Catches unknown malware</li>\n          <li>Harder for attackers to evade</li>\n          <li>TTP-level detection</li>\n        </ul>\n        <strong style=\"font-size:.8rem\">Weaknesses:</strong>\n        <ul style=\"margin:6px 0 0 14px;font-size:.8rem;line-height:1.8;color:var(--dim)\">\n          <li>Higher false positive rate</li>\n          <li>Requires tuning per environment</li>\n          <li>More compute intensive</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"card cc\">\n      <div class=\"clabel\">Detection Method 03</div>\n      <div class=\"ctitle\" style=\"color:var(--cyan2)\">ML / Anomaly</div>\n      <div class=\"cbody\">\n        <p style=\"margin-bottom:10px\">Statistical deviation from baseline. Machine learning models trained on normal behavior flag outliers. Used in modern UEBA and next-gen EDR.</p>\n        <strong style=\"font-size:.8rem\">Strengths:</strong>\n        <ul style=\"margin:6px 0 0 14px;font-size:.8rem;line-height:1.8;color:var(--dim)\">\n          <li>Detects subtle anomalies</li>\n          <li>No predefined signatures needed</li>\n          <li>Adapts to environment</li>\n        </ul>\n        <strong style=\"font-size:.8rem\">Weaknesses:</strong>\n        <ul style=\"margin:6px 0 0 14px;font-size:.8rem;line-height:1.8;color:var(--dim)\">\n          <li>Black box — hard to explain</li>\n          <li>Slow LttPD (slow attackers evade)</li>\n          <li>Requires large training baseline</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Data sources -->\n  <div class=\"card ca\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Visibility Foundation</div>\n    <div class=\"ctitle\" style=\"color:var(--amber)\">DETECTION DATA SOURCES</div>\n    <div class=\"cbody\" style=\"margin-bottom:12px\">A detection is only as good as the data it queries. These are the primary telemetry sources for enterprise detection:</div>\n    <table class=\"dTable\">\n      <tr><th>SOURCE</th><th>WHAT IT CAPTURES</th><th>KEY TOOL</th><th>COVERAGE GAP WITHOUT IT</th></tr>\n      <tr>\n        <td><strong>Windows Event Logs</strong></td>\n        <td>Logon events (4624/4625), process creation (4688), account changes, service installs (7045)</td>\n        <td><code>Get-WinEvent</code>, SIEM</td>\n        <td>Blind to authentication, lateral movement, privilege escalation</td>\n      </tr>\n      <tr>\n        <td><strong>Sysmon</strong></td>\n        <td>Process create (1), network connect (3), file create (11), registry (12-14), CreateRemoteThread (8)</td>\n        <td>Sysmon + SIEM</td>\n        <td>No process lineage, no injection detection, no DNS</td>\n      </tr>\n      <tr>\n        <td><strong>EDR Telemetry</strong></td>\n        <td>API calls, memory events, kernel events, file writes, registry, network — all correlated per process</td>\n        <td>CrowdStrike, SentinelOne, Defender</td>\n        <td>No behavioral analysis, no memory scanning</td>\n      </tr>\n      <tr>\n        <td><strong>DNS Logs</strong></td>\n        <td>All DNS queries from endpoints — reveals DGA, C2 beaconing, data exfil via DNS</td>\n        <td>DNS server logs, Zeek</td>\n        <td>Completely blind to DNS-based C2 and tunneling</td>\n      </tr>\n      <tr>\n        <td><strong>NetFlow / PCAP</strong></td>\n        <td>Network conversations, byte volumes, protocol metadata, JA3/JA3S fingerprints</td>\n        <td>Zeek, Suricata, ntopng</td>\n        <td>No lateral movement visibility, no exfil volume detection</td>\n      </tr>\n      <tr>\n        <td><strong>PowerShell Script Block Logs</strong></td>\n        <td>Full text of every PowerShell script executed — critical for LOLBin/fileless detection</td>\n        <td>Event 4104</td>\n        <td>Completely blind to PowerShell-based attacks</td>\n      </tr>\n    </table>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: EDR LOGIC\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-edr\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.1 — Endpoint Detection & Response //</div>\n      <div class=\"sh-title\">EDR Architecture & Detection Logic</div>\n      <div class=\"sh-desc\">How modern EDR products instrument the operating system, intercept API calls, correlate events, and generate alerts — and where attackers try to blind them.</div>\n    </div>\n  </div>\n\n  <!-- EDR Architecture -->\n  <div class=\"card ca\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">How EDR Works</div>\n    <div class=\"ctitle\" style=\"color:var(--amber)\">EDR INSTRUMENTATION LAYERS</div>\n    <div class=\"codeblock\" style=\"--cb-accent:var(--amber)\">\n      <span class=\"lb\">ARCHITECTURE</span>\n<span class=\"Y\">USER SPACE</span>\n┌─────────────────────────────────────────────────────────────────┐\n│  Malicious process                                              │\n│  └─ calls VirtualAllocEx()                                      │\n│       ↓                                                         │\n│  <span class=\"K\">Win32 API (kernel32.dll)</span>                                        │\n│  └─ routes to ntdll.dll                                         │\n│       ↓                                                         │\n│  <span class=\"K\">ntdll.dll (NtAllocateVirtualMemory)</span>                              │\n│  └─ <span class=\"Y\">← EDR DLL INJECTION HERE</span>                                    │\n│     EDR patches first 5 bytes with JMP to EDR inspection code   │\n│     EDR inspects call stack, arguments, context                 │\n│     EDR logs event, optionally BLOCKS call                      │\n│       ↓ (if allowed)                                            │\n│  <span class=\"K\">SYSCALL instruction</span> → transition to kernel                       │\n└─────────────────────────────────────────────────────────────────┘\n\n<span class=\"Y\">KERNEL SPACE</span>\n┌─────────────────────────────────────────────────────────────────┐\n│  <span class=\"K\">Kernel driver (EDR.sys)</span>                                         │\n│  ├─ Kernel callbacks: PsSetCreateProcessNotifyRoutine           │\n│  │   → fires on every process create/terminate                  │\n│  ├─ PsSetCreateThreadNotifyRoutine → every thread               │\n│  ├─ CmRegisterCallback → every registry operation               │\n│  ├─ ObRegisterCallbacks → object access (LSASS protection)      │\n│  └─ Minifilter driver → every file system operation             │\n│                                                                 │\n│  <span class=\"G\">ETW (Event Tracing for Windows)</span>                                  │\n│  ├─ Microsoft-Windows-Kernel-Process                            │\n│  ├─ Microsoft-Windows-Threat-Intelligence (ETWTI)               │\n│  └─ → captures memory alloc, injection, syscall patterns        │\n└─────────────────────────────────────────────────────────────────┘</div>\n  </div>\n\n  <!-- Sysmon config -->\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n    <div class=\"card cl\">\n      <div class=\"clabel\">Sysmon Configuration</div>\n      <div class=\"ctitle\" style=\"color:var(--lime2)\">HIGH-VALUE SYSMON EVENT IDs</div>\n      <table class=\"dTable\">\n        <tr><th>EVENT ID</th><th>DESCRIPTION</th><th>DETECTION VALUE</th></tr>\n        <tr><td class=\"tc-r\">1</td><td>Process Create (with cmdline, hashes, parent)</td><td class=\"tc-r\">CRITICAL</td></tr>\n        <tr><td class=\"tc-r\">3</td><td>Network Connection (process → IP:port)</td><td class=\"tc-r\">CRITICAL</td></tr>\n        <tr><td class=\"tc-y\">7</td><td>Image Loaded (DLL load events)</td><td class=\"tc-y\">HIGH</td></tr>\n        <tr><td class=\"tc-r\">8</td><td>CreateRemoteThread (source → target PID)</td><td class=\"tc-r\">CRITICAL</td></tr>\n        <tr><td class=\"tc-r\">10</td><td>ProcessAccess (LSASS reads = credential theft)</td><td class=\"tc-r\">CRITICAL</td></tr>\n        <tr><td class=\"tc-y\">11</td><td>FileCreate (file written — malware drops)</td><td class=\"tc-y\">HIGH</td></tr>\n        <tr><td class=\"tc-y\">12-14</td><td>RegistryEvent (keys set/deleted)</td><td class=\"tc-y\">HIGH</td></tr>\n        <tr><td class=\"tc-y\">22</td><td>DNSQuery (process → DNS lookup)</td><td class=\"tc-y\">HIGH</td></tr>\n        <tr><td class=\"tc-r\">25</td><td>ProcessTampering (hollowing detected)</td><td class=\"tc-r\">CRITICAL</td></tr>\n      </table>\n    </div>\n    <div class=\"card cl\">\n      <div class=\"clabel\">Sysmon Config — SwiftOnSecurity base</div>\n      <div class=\"ctitle\" style=\"color:var(--lime2)\">SYSMON XML CONFIGURATION</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--lime2)\">\n<span class=\"C\">&lt;!-- sysmon-config.xml — minimal high-value config --&gt;</span>\n&lt;<span class=\"K\">Sysmon</span> schemaversion=<span class=\"S\">\"4.90\"</span>&gt;\n  &lt;<span class=\"K\">EventFiltering</span>&gt;\n\n    <span class=\"C\">&lt;!-- Ev1: All process creation --&gt;</span>\n    &lt;<span class=\"K\">RuleGroup</span> groupRelation=<span class=\"S\">\"or\"</span>&gt;\n      &lt;<span class=\"F\">ProcessCreate</span> onmatch=<span class=\"S\">\"exclude\"</span>&gt;\n        &lt;<span class=\"V\">Image</span> condition=<span class=\"S\">\"is\"</span>&gt;\n          C:\\Windows\\System32\\svchost.exe\n        &lt;/<span class=\"V\">Image</span>&gt;\n      &lt;/<span class=\"F\">ProcessCreate</span>&gt;\n    &lt;/<span class=\"K\">RuleGroup</span>&gt;\n\n    <span class=\"C\">&lt;!-- Ev3: Network (exclude common noise) --&gt;</span>\n    &lt;<span class=\"K\">RuleGroup</span> groupRelation=<span class=\"S\">\"or\"</span>&gt;\n      &lt;<span class=\"F\">NetworkConnect</span> onmatch=<span class=\"S\">\"exclude\"</span>&gt;\n        &lt;<span class=\"V\">Image</span> condition=<span class=\"S\">\"is\"</span>&gt;\n          C:\\Windows\\System32\\svchost.exe\n        &lt;/<span class=\"V\">Image</span>&gt;\n      &lt;/<span class=\"F\">NetworkConnect</span>&gt;\n    &lt;/<span class=\"K\">RuleGroup</span>&gt;\n\n    <span class=\"C\">&lt;!-- Ev10: LSASS access (credential theft) --&gt;</span>\n    &lt;<span class=\"K\">RuleGroup</span> groupRelation=<span class=\"S\">\"or\"</span>&gt;\n      &lt;<span class=\"F\">ProcessAccess</span> onmatch=<span class=\"S\">\"include\"</span>&gt;\n        &lt;<span class=\"V\">TargetImage</span> condition=<span class=\"S\">\"endswith\"</span>&gt;\n          lsass.exe\n        &lt;/<span class=\"V\">TargetImage</span>&gt;\n      &lt;/<span class=\"F\">ProcessAccess</span>&gt;\n    &lt;/<span class=\"K\">RuleGroup</span>&gt;\n\n  &lt;/<span class=\"K\">EventFiltering</span>&gt;\n&lt;/<span class=\"K\">Sysmon</span>&gt;</div>\n    </div>\n  </div>\n\n  <!-- EDR bypass awareness -->\n  <div class=\"card cr\">\n    <div class=\"clabel\">Adversarial Awareness</div>\n    <div class=\"ctitle\" style=\"color:var(--red)\">EDR BYPASS TECHNIQUES — DEFENDER MUST KNOW</div>\n    <div class=\"cbody\" style=\"margin-bottom:12px\">Understanding how attackers attempt to blind EDR allows defenders to build compensating controls and detection for the bypass attempts themselves.</div>\n    <div class=\"g2\">\n      <div class=\"codeblock\" style=\"--cb-accent:var(--red)\">\n<span class=\"R\">BYPASS 1: Unhooking (direct syscalls)</span>\n<span class=\"C\"># EDR hooks ntdll.dll functions in user space</span>\n<span class=\"C\"># Attacker reads syscall numbers from disk copy of ntdll</span>\n<span class=\"C\"># Invokes syscall directly, bypassing EDR hooks</span>\n\n<span class=\"C\"># Detection:</span>\n<span class=\"G\">→</span> Monitor ETW ETWTI provider (kernel-level)\n<span class=\"G\">→</span> ETWTI is not in ntdll — hooks don't help attacker\n<span class=\"G\">→</span> Alert on: unusual ntdll reads from disk\n<span class=\"G\">→</span> Alert on: module loaded from non-standard path\n<span class=\"G\">→</span> EDR kernel driver callbacks fire regardless of hooking</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--red)\">\n<span class=\"R\">BYPASS 2: Process Injection into EDR</span>\n<span class=\"C\"># Inject code into the EDR agent process itself</span>\n<span class=\"C\"># EDR can't monitor its own memory writes</span>\n\n<span class=\"C\"># Mitigations:</span>\n<span class=\"G\">→</span> Protected Process Light (PPL) on EDR processes\n<span class=\"G\">→</span> ObRegisterCallbacks: EDR denies any handle to itself\n<span class=\"G\">→</span> Tamper protection (CrowdStrike, Defender)\n<span class=\"G\">→</span> Memory integrity (HVCI/Virtualization-based security)</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--red)\">\n<span class=\"R\">BYPASS 3: Kernel Driver Exploit</span>\n<span class=\"C\"># Use a vulnerable signed driver (BYOVD)</span>\n<span class=\"C\"># e.g. dell_hwinfo.sys, gdrv.sys</span>\n<span class=\"C\"># Get ring-0 execution → kill EDR driver</span>\n\n<span class=\"C\"># Detection:</span>\n<span class=\"G\">→</span> Block vulnerable driver hashes (WDAC policy)\n<span class=\"G\">→</span> Alert on unusual driver loads (Sysmon Ev6)\n<span class=\"G\">→</span> MSFT vulnerable driver blocklist (updated)\n<span class=\"G\">→</span> Alert on EDR process termination events</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--red)\">\n<span class=\"R\">BYPASS 4: Early Boot Execution</span>\n<span class=\"C\"># Execute before EDR driver loads</span>\n<span class=\"C\"># Bootkit in MBR/UEFI pre-loads malware</span>\n\n<span class=\"C\"># Mitigations:</span>\n<span class=\"G\">→</span> Secure Boot (firmware signature chain)\n<span class=\"G\">→</span> UEFI attestation\n<span class=\"G\">→</span> Measured boot (TPM-based integrity)\n<span class=\"G\">→</span> ELAM driver (anti-malware early launch)</div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: SIGMA RULES\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-sigma\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.2 — SIEM-Agnostic Detection Rules //</div>\n      <div class=\"sh-title\">Sigma Rule Authoring</div>\n      <div class=\"sh-desc\">Sigma is YARA for log events — write once, convert to Splunk SPL, Microsoft KQL, Elastic EQL, or any other SIEM format using sigma-cli. The industry standard for portable detection logic.</div>\n    </div>\n  </div>\n\n  <!-- Sigma anatomy -->\n  <div class=\"card cc\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Sigma Rule — Complete Anatomy</div>\n    <div class=\"ctitle\" style=\"color:var(--cyan2)\">RULE STRUCTURE WITH ANNOTATIONS</div>\n    <div class=\"sigma-block\">\n      <div class=\"sigma-hdr\">\n        <div class=\"sigma-tag\"></div>\n        <div class=\"sigma-title\">SIGMA — ANNOTATED RULE STRUCTURE</div>\n      </div>\n      <div class=\"sigma-body\"><span class=\"Y\">title:</span>     Suspicious Process Injection via CreateRemoteThread\n<span class=\"Y\">id:</span>        a1b2c3d4-e5f6-7890-abcd-ef1234567890  <span class=\"C\"># unique UUID</span>\n<span class=\"Y\">status:</span>    stable                                  <span class=\"C\"># experimental|test|stable|deprecated</span>\n<span class=\"Y\">description:</span> |\n    Detects classic process injection via CreateRemoteThread API call.\n    Covers DLL injection and shellcode injection patterns.\n    False positives: some legitimate software (AV, debuggers).\n\n<span class=\"Y\">author:</span>    analyst@org.com\n<span class=\"Y\">date:</span>      2025/01/15\n<span class=\"Y\">modified:</span>  2025/06/01\n\n<span class=\"Y\">references:</span>\n    - https://attack.mitre.org/techniques/T1055/\n    - https://docs.microsoft.com/en-us/sysinternals/downloads/sysmon\n\n<span class=\"Y\">tags:</span>\n    - attack.defense_evasion        <span class=\"C\"># TA0005</span>\n    - attack.privilege_escalation   <span class=\"C\"># TA0004 (often combined)</span>\n    - attack.t1055                  <span class=\"C\"># Process Injection</span>\n    - attack.t1055.001              <span class=\"C\"># DLL Injection subtechnique</span>\n\n<span class=\"Y\">logsource:</span>                          <span class=\"C\"># what log this targets</span>\n    category: create_remote_thread  <span class=\"C\"># Sysmon Event ID 8</span>\n    product: windows\n\n<span class=\"Y\">detection:</span>\n    selection:\n        <span class=\"CY\">SourceImage|endswith:</span>          <span class=\"C\"># process CREATING the thread</span>\n            - '\\explorer.exe'\n            - '\\winword.exe'\n            - '\\excel.exe'\n            - '\\powerpnt.exe'\n            - '\\outlook.exe'\n            - '\\notepad.exe'\n\n    <span class=\"CY\">filter_legit:</span>                      <span class=\"C\"># known-good exclusions</span>\n        <span class=\"CY\">TargetImage|endswith:</span>\n            - '\\svchost.exe'           <span class=\"C\"># legitimate svchost injections</span>\n        <span class=\"CY\">SourceImage|startswith:</span>\n            - 'C:\\Windows\\System32\\'  <span class=\"C\"># system processes</span>\n\n    <span class=\"CY\">condition:</span> selection <span class=\"K\">and not</span> filter_legit\n\n<span class=\"Y\">fields:</span>                             <span class=\"C\"># useful fields to include in alert</span>\n    - SourceImage\n    - TargetImage\n    - TargetProcessId\n    - StartAddress\n\n<span class=\"Y\">falsepositives:</span>\n    - Antivirus products (known good — add to filter)\n    - Debuggers (development environments only)\n    - Legitimate monitoring software (verify before filtering)\n\n<span class=\"Y\">level:</span> high                         <span class=\"C\"># informational|low|medium|high|critical</span>\n<span class=\"Y\">tlp:</span>  AMBER</div>\n    </div>\n  </div>\n\n  <!-- More Sigma rules -->\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n\n    <div>\n      <div class=\"rule-block\">\n        <div class=\"rule-header\">\n          <span class=\"rule-name\">Sigma — PowerShell Encoded Command</span>\n          <span class=\"rule-sev sev-high\">HIGH</span>\n        </div>\n        <div class=\"rule-body\"><span class=\"Y\">title:</span> PowerShell Encoded Command (Fileless Loader)\n<span class=\"Y\">id:</span>    b2c3d4e5-f6a7-8901-bcde-f12345678901\n<span class=\"Y\">status:</span> stable\n<span class=\"Y\">logsource:</span>\n    category: process_creation\n    product: windows\n<span class=\"Y\">detection:</span>\n    selection_pwsh:\n        <span class=\"CY\">Image|endswith:</span>\n            - '\\powershell.exe'\n            - '\\pwsh.exe'\n    selection_enc:\n        <span class=\"CY\">CommandLine|contains:</span>\n            - ' -EncodedCommand '\n            - ' -enc '\n            - ' -e '\n    selection_bypass:\n        <span class=\"CY\">CommandLine|contains:</span>\n            - 'bypass'\n            - 'hidden'\n            - 'noprofile'\n    <span class=\"CY\">condition:</span> selection_pwsh <span class=\"K\">and</span> selection_enc\n               <span class=\"K\">and</span> selection_bypass\n<span class=\"Y\">level:</span> high\n<span class=\"Y\">tags:</span> [attack.execution, attack.t1059.001]</div>\n      </div>\n\n      <div class=\"rule-block\" style=\"margin-top:8px\">\n        <div class=\"rule-header\">\n          <span class=\"rule-name\">Sigma — WMI Persistence (T1546.003)</span>\n          <span class=\"rule-sev sev-crit\">CRITICAL</span>\n        </div>\n        <div class=\"rule-body\"><span class=\"Y\">title:</span> WMI Event Subscription Persistence\n<span class=\"Y\">id:</span>    c3d4e5f6-a7b8-9012-cdef-123456789012\n<span class=\"Y\">status:</span> stable\n<span class=\"Y\">logsource:</span>\n    product: windows\n    service: wmi\n<span class=\"Y\">detection:</span>\n    selection:\n        <span class=\"CY\">EventType:</span> ExtrinsicEvent\n        <span class=\"CY\">Destination|contains:</span>\n            - 'ActiveScriptEventConsumer'\n            - 'CommandLineEventConsumer'\n    <span class=\"CY\">condition:</span> selection\n<span class=\"Y\">falsepositives:</span>\n    - SCCM/WDS legitimate WMI subscriptions\n    - Some monitoring software\n<span class=\"Y\">level:</span> critical\n<span class=\"Y\">tags:</span> [attack.persistence, attack.t1546.003]</div>\n      </div>\n    </div>\n\n    <div>\n      <div class=\"rule-block\">\n        <div class=\"rule-header\">\n          <span class=\"rule-name\">Sigma — Credential Theft (LSASS Access)</span>\n          <span class=\"rule-sev sev-crit\">CRITICAL</span>\n        </div>\n        <div class=\"rule-body\"><span class=\"Y\">title:</span> LSASS Memory Access — Credential Theft\n<span class=\"Y\">id:</span>    d4e5f6a7-b8c9-0123-defa-234567890123\n<span class=\"Y\">status:</span> stable\n<span class=\"Y\">logsource:</span>\n    category: process_access   <span class=\"C\"># Sysmon Ev10</span>\n    product: windows\n<span class=\"Y\">detection:</span>\n    selection:\n        <span class=\"CY\">TargetImage|endswith:</span> '\\lsass.exe'\n        <span class=\"CY\">GrantedAccess|contains:</span>\n            - '0x1010'   <span class=\"C\"># PROCESS_VM_READ</span>\n            - '0x1410'   <span class=\"C\"># + PROCESS_QUERY_INFO</span>\n            - '0x1438'   <span class=\"C\"># full access</span>\n    filter_legit:\n        <span class=\"CY\">SourceImage|startswith:</span>\n            - 'C:\\Windows\\System32\\'\n            - 'C:\\Program Files\\CrowdStrike\\'\n    <span class=\"CY\">condition:</span> selection <span class=\"K\">and not</span> filter_legit\n<span class=\"Y\">level:</span> critical\n<span class=\"Y\">tags:</span> [attack.credential_access, attack.t1003.001]</div>\n      </div>\n\n      <div class=\"rule-block\" style=\"margin-top:8px\">\n        <div class=\"rule-header\">\n          <span class=\"rule-name\">Sigma — VSS Shadow Copy Deletion</span>\n          <span class=\"rule-sev sev-crit\">CRITICAL</span>\n        </div>\n        <div class=\"rule-body\"><span class=\"Y\">title:</span> Volume Shadow Copy Deletion (Ransomware)\n<span class=\"Y\">id:</span>    e5f6a7b8-c9d0-1234-efab-345678901234\n<span class=\"Y\">status:</span> stable\n<span class=\"Y\">logsource:</span>\n    category: process_creation\n    product: windows\n<span class=\"Y\">detection:</span>\n    <span class=\"CY\">sel_vssadmin:</span>\n        <span class=\"CY\">Image|endswith:</span> '\\vssadmin.exe'\n        <span class=\"CY\">CommandLine|contains:</span> 'delete shadows'\n    <span class=\"CY\">sel_wmic:</span>\n        <span class=\"CY\">Image|endswith:</span> '\\wmic.exe'\n        <span class=\"CY\">CommandLine|contains|all:</span>\n            - 'shadowcopy'\n            - 'delete'\n    <span class=\"CY\">sel_wbadmin:</span>\n        <span class=\"CY\">CommandLine|contains|all:</span>\n            - 'wbadmin'\n            - 'delete'\n            - 'catalog'\n    <span class=\"CY\">condition:</span> sel_vssadmin <span class=\"K\">or</span>\n               sel_wmic <span class=\"K\">or</span>\n               sel_wbadmin\n<span class=\"Y\">level:</span> critical\n<span class=\"Y\">tags:</span> [attack.impact, attack.t1490]</div>\n      </div>\n    </div>\n\n  </div>\n\n  <!-- sigma-cli conversion -->\n  <div class=\"card cc\">\n    <div class=\"clabel\">Sigma CLI — Rule Conversion</div>\n    <div class=\"ctitle\" style=\"color:var(--cyan2)\">CONVERT SIGMA TO ANY SIEM FORMAT</div>\n    <div class=\"codeblock\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"lb\">BASH</span>\n<span class=\"C\"># Install sigma-cli</span>\n<span class=\"F\">pip</span> install sigma-cli\n\n<span class=\"C\"># Convert to Microsoft Sentinel KQL</span>\n<span class=\"F\">sigma</span> convert -t microsoft365defender rule.yml\n\n<span class=\"C\"># Convert to Splunk SPL</span>\n<span class=\"F\">sigma</span> convert -t splunk rule.yml\n\n<span class=\"C\"># Convert to Elastic EQL</span>\n<span class=\"F\">sigma</span> convert -t elasticsearch rule.yml\n\n<span class=\"C\"># Convert entire rules directory to Splunk</span>\n<span class=\"F\">sigma</span> convert -t splunk -r /rules/windows/ > splunk_rules.conf\n\n<span class=\"C\"># Validate rule syntax</span>\n<span class=\"F\">sigma</span> check rule.yml\n\n<span class=\"C\"># List supported backends</span>\n<span class=\"F\">sigma</span> list backends\n\n<span class=\"C\"># Output: KQL (from LSASS rule above)</span>\n<span class=\"H\">DeviceEvents\n| where ActionType == \"OpenProcess\"\n| where FileName endswith \"lsass.exe\"\n| where ProcessAccessMask has_any (\"0x1010\",\"0x1410\",\"0x1438\")\n| where not InitiatingProcessFolderPath startswith @\"C:\\Windows\\System32\\\"</span></div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: SIEM QUERIES\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-siem\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.3 — SIEM Query Languages //</div>\n      <div class=\"sh-title\">KQL & SPL Detection Queries</div>\n      <div class=\"sh-desc\">Production-ready queries for Microsoft Sentinel (KQL) and Splunk (SPL) covering the highest-value detection scenarios. Each query includes tuning notes and ATT&CK mapping.</div>\n    </div>\n  </div>\n\n  <div class=\"itabs\">\n    <button class=\"itab active\" onclick=\"iTab('kql',this)\">KQL — Sentinel</button>\n    <button class=\"itab\" onclick=\"iTab('spl',this)\">SPL — Splunk</button>\n    <button class=\"itab\" onclick=\"iTab('eql',this)\">EQL — Elastic</button>\n  </div>\n\n  <div class=\"ipanel active\" id=\"ip-kql\">\n\n    <div class=\"rule-block\" style=\"margin-bottom:10px\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">KQL — Beaconing Detection (C2 Timing)</span>\n        <span class=\"rule-sev sev-high\">T1071 · C2</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">// Detect regular beaconing patterns — statistical periodicity analysis</span>\n<span class=\"CY\">// Tuning: adjust MinBeaconCount and StdDevThreshold for environment</span>\n\n<span class=\"K\">let</span> <span class=\"V\">LookbackWindow</span> = <span class=\"N\">24h</span>;\n<span class=\"K\">let</span> <span class=\"V\">MinBeaconCount</span> = <span class=\"N\">10</span>;      <span class=\"C\">// min connections to flag</span>\n<span class=\"K\">let</span> <span class=\"V\">StdDevThreshold</span> = <span class=\"N\">5.0</span>;   <span class=\"C\">// low stddev = regular interval</span>\n\n<span class=\"F\">DeviceNetworkEvents</span>\n<span class=\"K\">| where</span> TimeGenerated &gt; ago(<span class=\"V\">LookbackWindow</span>)\n<span class=\"K\">| where</span> RemotePort <span class=\"K\">in</span> (<span class=\"N\">80</span>, <span class=\"N\">443</span>, <span class=\"N\">8080</span>, <span class=\"N\">8443</span>)\n<span class=\"K\">| summarize</span>\n    ConnectionCount = count(),\n    IntervalSeconds = stdev(bin(TimeGenerated, <span class=\"N\">1s</span>))\n    <span class=\"K\">by</span> DeviceName, InitiatingProcessFileName, RemoteIP, RemotePort\n<span class=\"K\">| where</span> ConnectionCount &gt; <span class=\"V\">MinBeaconCount</span>\n<span class=\"K\">| where</span> IntervalSeconds &lt; <span class=\"V\">StdDevThreshold</span>  <span class=\"C\">// low stddev = periodic</span>\n<span class=\"K\">| where</span> InitiatingProcessFileName !in~ (\n    <span class=\"S\">\"chrome.exe\"</span>, <span class=\"S\">\"firefox.exe\"</span>, <span class=\"S\">\"msedge.exe\"</span>, <span class=\"S\">\"svchost.exe\"</span>\n)\n<span class=\"K\">| project</span> DeviceName, InitiatingProcessFileName,\n          RemoteIP, RemotePort, ConnectionCount, IntervalSeconds\n<span class=\"K\">| order by</span> IntervalSeconds <span class=\"K\">asc</span>  <span class=\"C\">// most regular first</span></div>\n    </div>\n\n    <div class=\"rule-block\" style=\"margin-bottom:10px\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">KQL — Lateral Movement via WMI/PsExec</span>\n        <span class=\"rule-sev sev-high\">T1021 · Lateral Movement</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">// Detect lateral movement via WMI remote execution and PsExec patterns</span>\n<span class=\"F\">SecurityEvent</span>\n<span class=\"K\">| where</span> EventID == <span class=\"N\">4688</span>                  <span class=\"C\">// Process creation</span>\n<span class=\"K\">| where</span> ParentProcessName <span class=\"K\">contains</span> <span class=\"S\">\"WmiPrvSE\"</span>\n<span class=\"K\">| where</span> NewProcessName !endswith <span class=\"K\">in</span> (\n    <span class=\"S\">\"mofcomp.exe\"</span>, <span class=\"S\">\"wmiprvse.exe\"</span>, <span class=\"S\">\"unsecapp.exe\"</span>\n)\n<span class=\"K\">| project</span> TimeGenerated, Computer, Account,\n          NewProcessName, CommandLine, ParentProcessName\n<span class=\"K\">| union</span> (\n    <span class=\"C\">// PsExec pattern: PSEXESVC service creation</span>\n    <span class=\"F\">SecurityEvent</span>\n    <span class=\"K\">| where</span> EventID == <span class=\"N\">7045</span>\n    <span class=\"K\">| where</span> ServiceName <span class=\"K\">contains</span> <span class=\"S\">\"PSEXESVC\"</span>\n    <span class=\"K\">   or</span>  ServiceFileName <span class=\"K\">contains</span> <span class=\"S\">\"\\\\ADMIN$\\\\\"</span>\n    <span class=\"K\">| project</span> TimeGenerated, Computer,\n              ServiceName, ServiceFileName\n)\n<span class=\"K\">| order by</span> TimeGenerated <span class=\"K\">desc</span></div>\n    </div>\n\n    <div class=\"rule-block\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">KQL — Impossible Travel Detection (UEBA)</span>\n        <span class=\"rule-sev sev-high\">T1078 · Account Abuse</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">// Detect logons from geographically impossible locations within short time window</span>\n<span class=\"F\">SigninLogs</span>\n<span class=\"K\">| where</span> ResultType == <span class=\"S\">\"0\"</span>              <span class=\"C\">// successful sign-ins only</span>\n<span class=\"K\">| project</span> TimeGenerated, UserPrincipalName,\n          Location, IPAddress, AppDisplayName\n<span class=\"K\">| sort by</span> UserPrincipalName, TimeGenerated <span class=\"K\">asc</span>\n<span class=\"K\">| serialize</span>\n<span class=\"K\">| extend</span>\n    PrevTime     = prev(TimeGenerated),\n    PrevLocation = prev(Location),\n    PrevUser     = prev(UserPrincipalName)\n<span class=\"K\">| where</span> UserPrincipalName == PrevUser      <span class=\"C\">// same user</span>\n<span class=\"K\">| extend</span> TimeDiffMinutes = datetime_diff(<span class=\"S\">'minute'</span>, TimeGenerated, PrevTime)\n<span class=\"K\">| where</span> TimeDiffMinutes &lt; <span class=\"N\">60</span>              <span class=\"C\">// within 1 hour</span>\n<span class=\"K\">| where</span> Location != PrevLocation          <span class=\"C\">// different country</span>\n<span class=\"K\">| where</span> PrevLocation !has <span class=\"S\">\"VPN\"</span>           <span class=\"C\">// exclude known VPN</span>\n<span class=\"K\">| project</span> UserPrincipalName,\n          PrevLocation, Location,\n          TimeDiffMinutes, IPAddress, AppDisplayName\n<span class=\"K\">| where</span> TimeDiffMinutes &gt; <span class=\"N\">0</span></div>\n    </div>\n\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-spl\">\n\n    <div class=\"rule-block\" style=\"margin-bottom:10px\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">SPL — DGA Detection (DNS NXDOMAIN Storm)</span>\n        <span class=\"rule-sev sev-high\">T1568.002 · DGA</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">| Detect DGA bots: high NXDOMAIN ratio + high-entropy domains</span>\n\n<span class=\"K\">index</span>=dns sourcetype=dns\n<span class=\"K\">| eval</span> domain_len = len(query)\n<span class=\"K\">| where</span> domain_len > <span class=\"N\">20</span>              <span class=\"C\">/* long labels typical of DGA */</span>\n<span class=\"K\">| stats</span>\n    count <span class=\"K\">as</span> total,\n    sum(eval(if(reply_code=\"NXDOMAIN\",<span class=\"N\">1</span>,<span class=\"N\">0</span>))) <span class=\"K\">as</span> nxdomain_count\n    <span class=\"K\">by</span> src_ip, dest\n<span class=\"K\">| eval</span> nxdomain_ratio = round(nxdomain_count / total * <span class=\"N\">100</span>, <span class=\"N\">1</span>)\n<span class=\"K\">| where</span> nxdomain_ratio > <span class=\"N\">70</span>           <span class=\"C\">/* &gt;70% NXDOMAIN = DGA bot */</span>\n<span class=\"K\">| where</span> total > <span class=\"N\">50</span>                     <span class=\"C\">/* minimum query volume */</span>\n<span class=\"K\">| sort</span> -nxdomain_ratio\n<span class=\"K\">| table</span> src_ip, dest, total, nxdomain_count, nxdomain_ratio</div>\n    </div>\n\n    <div class=\"rule-block\" style=\"margin-bottom:10px\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">SPL — Ransomware: File Encryption Storm</span>\n        <span class=\"rule-sev sev-crit\">T1486 · Ransomware</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">| Detect bulk file rename/write activity typical of ransomware encryption</span>\n\n<span class=\"K\">index</span>=sysmon EventCode=<span class=\"N\">11</span>            <span class=\"C\">/* Sysmon FileCreate events */</span>\n<span class=\"K\">| stats</span>\n    count <span class=\"K\">as</span> file_writes,\n    dc(TargetFilename) <span class=\"K\">as</span> unique_files,\n    values(TargetFilename) <span class=\"K\">as</span> files\n    <span class=\"K\">by</span> Image, ComputerName, _time span=<span class=\"N\">1m</span>\n<span class=\"K\">| where</span> file_writes > <span class=\"N\">100</span>             <span class=\"C\">/* &gt;100 writes/minute */</span>\n<span class=\"K\">| join</span> Image [\n    <span class=\"K\">search</span> <span class=\"K\">index</span>=sysmon EventCode=<span class=\"N\">1</span>\n    | table Image, CommandLine, ParentImage\n]\n<span class=\"K\">| eval</span> has_ransom_ext = if(\n    match(files, <span class=\"S\">\"\\.(locked|encrypted|enc|cry|xxx|zzz)$\"</span>), <span class=\"N\">1</span>, <span class=\"N\">0</span>\n)\n<span class=\"K\">| where</span> has_ransom_ext == <span class=\"N\">1</span> <span class=\"K\">OR</span> file_writes > <span class=\"N\">500</span>\n<span class=\"K\">| table</span> ComputerName, Image, CommandLine, file_writes, has_ransom_ext</div>\n    </div>\n\n    <div class=\"rule-block\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">SPL — Pass-the-Hash Detection</span>\n        <span class=\"rule-sev sev-crit\">T1550.002 · PtH</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">| Pass-the-Hash: NTLM auth with different source IP than expected</span>\n<span class=\"C\">| EventID 4624 LogonType 3 (network) + NTLM + no password hash</span>\n\n<span class=\"K\">index</span>=wineventlog EventCode=<span class=\"N\">4624</span>\n    LogonType=<span class=\"N\">3</span>\n    AuthenticationPackageName=NTLM\n<span class=\"K\">| stats</span>\n    count <span class=\"K\">as</span> auth_count,\n    dc(IpAddress) <span class=\"K\">as</span> unique_sources,\n    values(IpAddress) <span class=\"K\">as</span> src_ips,\n    values(TargetUserName) <span class=\"K\">as</span> users\n    <span class=\"K\">by</span> ComputerName, WorkstationName, _time span=<span class=\"N\">10m</span>\n<span class=\"K\">| where</span> unique_sources > <span class=\"N\">1</span>            <span class=\"C\">/* same account, multiple IPs */</span>\n<span class=\"K\">| lookup</span> known_admin_hosts ComputerName <span class=\"K\">OUTPUT</span> is_admin_host\n<span class=\"K\">| where</span> is_admin_host != <span class=\"S\">\"true\"</span>\n<span class=\"K\">| table</span> ComputerName, users, src_ips, auth_count, unique_sources</div>\n    </div>\n\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-eql\">\n    <div class=\"rule-block\" style=\"margin-bottom:10px\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">EQL — Office Process Spawning Shell</span>\n        <span class=\"rule-sev sev-crit\">T1566 · Phishing → Execution</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">// Elastic EQL: Office application spawning cmd/PowerShell (macro execution)</span>\n\n<span class=\"K\">sequence by</span> host.name <span class=\"K\">with maxspan</span>=<span class=\"N\">5m</span>\n  [process <span class=\"K\">where</span>\n    process.name : (<span class=\"S\">\"winword.exe\"</span>, <span class=\"S\">\"excel.exe\"</span>,\n                   <span class=\"S\">\"powerpnt.exe\"</span>, <span class=\"S\">\"outlook.exe\"</span>)\n    <span class=\"K\">and</span> event.type == <span class=\"S\">\"start\"</span>\n  ]\n  [process <span class=\"K\">where</span>\n    process.name : (<span class=\"S\">\"cmd.exe\"</span>, <span class=\"S\">\"powershell.exe\"</span>, <span class=\"S\">\"wscript.exe\"</span>,\n                   <span class=\"S\">\"mshta.exe\"</span>, <span class=\"S\">\"certutil.exe\"</span>, <span class=\"S\">\"regsvr32.exe\"</span>)\n    <span class=\"K\">and</span> event.type == <span class=\"S\">\"start\"</span>\n    <span class=\"K\">and not</span> process.command_line : <span class=\"S\">\"*</span>\\<span class=\"S\">Microsoft Office*\"</span>\n  ]</div>\n    </div>\n    <div class=\"rule-block\">\n      <div class=\"rule-header\">\n        <span class=\"rule-name\">EQL — Credential Dumping Sequence</span>\n        <span class=\"rule-sev sev-crit\">T1003 · Credential Dumping</span>\n      </div>\n      <div class=\"rule-body\"><span class=\"C\">// Mimikatz-style LSASS access pattern</span>\n<span class=\"K\">sequence by</span> host.name, process.entity_id <span class=\"K\">with maxspan</span>=<span class=\"N\">30s</span>\n  [process <span class=\"K\">where</span>\n    event.type == <span class=\"S\">\"start\"</span>\n    <span class=\"K\">and not</span> process.code_signature.trusted == <span class=\"K\">true</span>\n  ]\n  [process <span class=\"K\">where</span>\n    event.category == <span class=\"S\">\"process\"</span>\n    <span class=\"K\">and</span> event.action == <span class=\"S\">\"accessed\"</span>\n    <span class=\"K\">and</span> winlog.event_data.TargetImage : <span class=\"S\">\"*lsass.exe\"</span>\n    <span class=\"K\">and</span> winlog.event_data.GrantedAccess : (\n        <span class=\"S\">\"0x1010\"</span>, <span class=\"S\">\"0x1410\"</span>, <span class=\"S\">\"0x1438\"</span>, <span class=\"S\">\"0x143a\"</span>\n    )\n  ]</div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: THREAT HUNTING\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-hunting\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.4 — Proactive Threat Detection //</div>\n      <div class=\"sh-title\">Threat Hunting</div>\n      <div class=\"sh-desc\">Structured, hypothesis-driven hunting for threats that evade existing detections. The difference between reactive (alert-driven) and proactive (assumption-of-breach) security posture.</div>\n    </div>\n  </div>\n\n  <div class=\"hunt-pipe\" style=\"margin-bottom:14px\">\n    <div class=\"hp-step\">\n      <div class=\"hp-n\">01</div><div class=\"hp-icon\">💡</div>\n      <div class=\"hp-name\">HYPOTHESIS</div>\n      <div class=\"hp-desc\">\"Attacker has established persistence via scheduled tasks\"</div>\n    </div>\n    <div class=\"hp-step\">\n      <div class=\"hp-n\">02</div><div class=\"hp-icon\">🗺️</div>\n      <div class=\"hp-name\">ATT&CK MAP</div>\n      <div class=\"hp-desc\">T1053.005 — Scheduled Task/Job</div>\n    </div>\n    <div class=\"hp-step\">\n      <div class=\"hp-n\">03</div><div class=\"hp-icon\">📊</div>\n      <div class=\"hp-name\">DATA SOURCES</div>\n      <div class=\"hp-desc\">Sysmon Ev1, Ev4698, Windows Ev4698/4702</div>\n    </div>\n    <div class=\"hp-step\">\n      <div class=\"hp-n\">04</div><div class=\"hp-icon\">🔍</div>\n      <div class=\"hp-name\">HUNT</div>\n      <div class=\"hp-desc\">Query SIEM, pivot on findings</div>\n    </div>\n    <div class=\"hp-step\">\n      <div class=\"hp-n\">05</div><div class=\"hp-icon\">🔬</div>\n      <div class=\"hp-name\">TRIAGE</div>\n      <div class=\"hp-desc\">Investigate hits, eliminate false positives</div>\n    </div>\n    <div class=\"hp-step\">\n      <div class=\"hp-n\">06</div><div class=\"hp-icon\">🛡️</div>\n      <div class=\"hp-name\">PRODUCTIZE</div>\n      <div class=\"hp-desc\">Convert hunt to Sigma/KQL detection rule</div>\n    </div>\n  </div>\n\n  <!-- Hunt 1: Scheduled Tasks -->\n  <div class=\"card ca\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Hunt 01 — T1053.005</div>\n    <div class=\"ctitle\" style=\"color:var(--amber)\">SCHEDULED TASK PERSISTENCE HUNT</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\"><strong>Hypothesis:</strong> Attacker created a scheduled task pointing to a non-standard executable path (AppData, Temp, ProgramData) to maintain persistence.</div>\n    <div class=\"g2\">\n      <div class=\"codeblock\" style=\"--cb-accent:var(--amber)\">\n<span class=\"lb\">KQL</span>\n<span class=\"C\">// Hunt: Scheduled tasks in suspicious paths</span>\n<span class=\"F\">SecurityEvent</span>\n<span class=\"K\">| where</span> EventID == <span class=\"N\">4698</span>    <span class=\"C\">// task created</span>\n<span class=\"K\">   or</span>  EventID == <span class=\"N\">4702</span>    <span class=\"C\">// task modified</span>\n<span class=\"K\">| extend</span> TaskXML = extractjson(\n    <span class=\"S\">\"$.EventData.TaskContent\"</span>, EventData\n)\n<span class=\"K\">| where</span> TaskXML <span class=\"K\">contains</span> <span class=\"S\">@\"\\AppData\\\"</span>\n    <span class=\"K\">or</span>  TaskXML <span class=\"K\">contains</span> <span class=\"S\">@\"\\Temp\\\"</span>\n    <span class=\"K\">or</span>  TaskXML <span class=\"K\">contains</span> <span class=\"S\">@\"\\ProgramData\\\"</span>\n    <span class=\"K\">or</span>  TaskXML <span class=\"K\">contains</span> <span class=\"S\">\"powershell\"</span>\n    <span class=\"K\">or</span>  TaskXML <span class=\"K\">contains</span> <span class=\"S\">\"mshta\"</span>\n<span class=\"K\">| project</span> TimeGenerated,\n          Computer, SubjectUserName,\n          EventID, TaskXML\n<span class=\"K\">| order by</span> TimeGenerated <span class=\"K\">desc</span></div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--amber)\">\n<span class=\"lb\">POWERSHELL — LIVE</span>\n<span class=\"C\"># Hunt scheduled tasks on live system</span>\n<span class=\"F\">Get-ScheduledTask</span> <span class=\"K\">|</span>\n  <span class=\"F\">Where-Object</span> { <span class=\"V\">$_</span>.State <span class=\"K\">-ne</span> <span class=\"S\">'Disabled'</span> } <span class=\"K\">|</span>\n  <span class=\"F\">ForEach-Object</span> {\n    <span class=\"V\">$task</span> = <span class=\"V\">$_</span>\n    <span class=\"V\">$action</span> = <span class=\"V\">$task</span>.Actions | <span class=\"F\">Select-Object</span> -First <span class=\"N\">1</span>\n    [PSCustomObject]@{\n      Name     = <span class=\"V\">$task</span>.TaskName\n      Path     = <span class=\"V\">$task</span>.TaskPath\n      Execute  = <span class=\"V\">$action</span>.Execute\n      Arguments= <span class=\"V\">$action</span>.Arguments\n    }\n  } <span class=\"K\">|</span>\n  <span class=\"F\">Where-Object</span> {\n    <span class=\"V\">$_</span>.Execute <span class=\"K\">-match</span>\n      <span class=\"S\">'AppData|Temp|ProgramData|powershell|mshta|wscript'</span>\n  } <span class=\"K\">|</span>\n  <span class=\"F\">Format-Table</span> -AutoSize</div>\n    </div>\n  </div>\n\n  <!-- Hunt 2: LOLBin abuse -->\n  <div class=\"card cl\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Hunt 02 — T1218 / T1059</div>\n    <div class=\"ctitle\" style=\"color:var(--lime2)\">LOLBIN ABUSE HUNT</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\"><strong>Hypothesis:</strong> Attacker is using signed Windows binaries (LOLBins) to execute malicious code, evading application whitelisting.</div>\n    <div class=\"codeblock\" style=\"--cb-accent:var(--lime2)\">\n<span class=\"lb\">KQL</span>\n<span class=\"C\">// Hunt: Living-Off-The-Land Binary (LOLBin) execution with suspicious patterns</span>\n<span class=\"K\">let</span> <span class=\"V\">lolbins</span> = dynamic([\n    <span class=\"S\">\"mshta.exe\"</span>, <span class=\"S\">\"regsvr32.exe\"</span>, <span class=\"S\">\"certutil.exe\"</span>, <span class=\"S\">\"wmic.exe\"</span>,\n    <span class=\"S\">\"bitsadmin.exe\"</span>, <span class=\"S\">\"msiexec.exe\"</span>, <span class=\"S\">\"cmstp.exe\"</span>, <span class=\"S\">\"installutil.exe\"</span>,\n    <span class=\"S\">\"regasm.exe\"</span>, <span class=\"S\">\"regsvcs.exe\"</span>, <span class=\"S\">\"rundll32.exe\"</span>, <span class=\"S\">\"odbcconf.exe\"</span>\n]);\n<span class=\"K\">let</span> <span class=\"V\">suspicious_patterns</span> = dynamic([\n    <span class=\"S\">\"http\"</span>, <span class=\"S\">\"\\\\\\\\10.\"</span>, <span class=\"S\">\"\\\\\\\\192.\"</span>,    <span class=\"C\">// network paths</span>\n    <span class=\"S\">\"AppData\"</span>, <span class=\"S\">\"Temp\"</span>, <span class=\"S\">\"ProgramData\"</span>, <span class=\"C\">// user-writable paths</span>\n    <span class=\"S\">\"decode\"</span>, <span class=\"S\">\"urlcache\"</span>, <span class=\"S\">\"split\"</span>     <span class=\"C\">// certutil abuse patterns</span>\n]);\n\n<span class=\"F\">DeviceProcessEvents</span>\n<span class=\"K\">| where</span> FileName <span class=\"K\">in~</span> (<span class=\"V\">lolbins</span>)\n<span class=\"K\">| where</span> ProcessCommandLine <span class=\"K\">has_any</span> (<span class=\"V\">suspicious_patterns</span>)\n<span class=\"K\">| summarize</span> count() <span class=\"K\">by</span>\n    DeviceName, FileName,\n    ProcessCommandLine, InitiatingProcessFileName\n<span class=\"K\">| order by</span> count_ <span class=\"K\">desc</span></div>\n  </div>\n\n  <!-- Hunt 3: Domain Controller recon -->\n  <div class=\"card cc\">\n    <div class=\"clabel\">Hunt 03 — T1087 / T1069</div>\n    <div class=\"ctitle\" style=\"color:var(--cyan2)\">ACTIVE DIRECTORY RECONNAISSANCE HUNT</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\"><strong>Hypothesis:</strong> Attacker is performing AD recon to identify targets for lateral movement and privilege escalation.</div>\n    <div class=\"codeblock\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"lb\">KQL</span>\n<span class=\"C\">// Hunt: LDAP queries and AD enum activity</span>\n<span class=\"F\">IdentityQueryEvents</span>\n<span class=\"K\">| where</span> QueryType <span class=\"K\">in</span> (\n    <span class=\"S\">\"LdapSearch\"</span>, <span class=\"S\">\"SamrSamEnumerateDomainsInSamServer\"</span>,\n    <span class=\"S\">\"Kerberos TGT\"</span>\n)\n<span class=\"K\">| summarize</span>\n    QueryCount    = count(),\n    UniqueTargets = dcount(QueryTarget),\n    QueryTypes    = make_set(QueryType)\n    <span class=\"K\">by</span> DeviceName, AccountName, bin(TimeGenerated, <span class=\"N\">1h</span>)\n<span class=\"K\">| where</span> QueryCount > <span class=\"N\">50</span>\n<span class=\"K\">| where</span> UniqueTargets > <span class=\"N\">10</span>\n<span class=\"K\">| union</span> (\n    <span class=\"C\">// net.exe enumeration commands</span>\n    <span class=\"F\">DeviceProcessEvents</span>\n    <span class=\"K\">| where</span> FileName <span class=\"K\">in~</span> (<span class=\"S\">\"net.exe\"</span>, <span class=\"S\">\"net1.exe\"</span>)\n    <span class=\"K\">| where</span> ProcessCommandLine <span class=\"K\">has_any</span> (\n        <span class=\"S\">\"group\"</span>, <span class=\"S\">\"user\"</span>, <span class=\"S\">\"accounts\"</span>, <span class=\"S\">\"localgroup\"</span>,\n        <span class=\"S\">\"domain admins\"</span>, <span class=\"S\">\"enterprise admins\"</span>\n    )\n    <span class=\"K\">| project</span> TimeGenerated, DeviceName,\n              AccountName = InitiatingProcessAccountName,\n              QueryCount = <span class=\"N\">1</span>, UniqueTargets = <span class=\"N\">1</span>,\n              QueryTypes = pack_array(ProcessCommandLine)\n)\n<span class=\"K\">| order by</span> QueryCount <span class=\"K\">desc</span></div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: FORENSICS\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-forensics\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.5 — Digital Forensics //</div>\n      <div class=\"sh-title\">Forensic Investigation</div>\n      <div class=\"sh-desc\">Evidence-preserving investigation techniques — artifact collection, timeline reconstruction, registry forensics, and Windows/Linux artifact locations that malware leaves behind.</div>\n    </div>\n  </div>\n\n  <div class=\"itabs\">\n    <button class=\"itab active\" onclick=\"iTab('artifacts',this)\">Windows Artifacts</button>\n    <button class=\"itab\" onclick=\"iTab('timeline',this)\">Timeline Analysis</button>\n    <button class=\"itab\" onclick=\"iTab('linux-artifacts',this)\">Linux Artifacts</button>\n  </div>\n\n  <div class=\"ipanel active\" id=\"ip-artifacts\">\n    <div class=\"card ca\" style=\"margin-bottom:14px\">\n      <div class=\"clabel\">Windows Forensic Artifacts</div>\n      <div class=\"ctitle\" style=\"color:var(--amber)\">HIGH-VALUE ARTIFACT LOCATIONS</div>\n      <table class=\"dTable\">\n        <tr><th>ARTIFACT</th><th>LOCATION</th><th>WHAT IT TELLS YOU</th><th>TOOL</th></tr>\n        <tr>\n          <td><strong>Prefetch</strong></td>\n          <td><code>C:\\Windows\\Prefetch\\*.pf</code></td>\n          <td>Executables that ran (last 8 timestamps, run count)</td>\n          <td>WinPrefetchView, PECmd</td>\n        </tr>\n        <tr>\n          <td><strong>Shimcache</strong></td>\n          <td>Registry: <code>HKLM\\SYSTEM\\...\\AppCompatCache</code></td>\n          <td>Executables that existed on disk (even if deleted)</td>\n          <td>AppCompatCacheParser</td>\n        </tr>\n        <tr>\n          <td><strong>AmCache</strong></td>\n          <td><code>C:\\Windows\\AppCompat\\Programs\\Amcache.hve</code></td>\n          <td>Execution history with hashes — survived deletion</td>\n          <td>AmcacheParser</td>\n        </tr>\n        <tr>\n          <td><strong>MFT ($MFT)</strong></td>\n          <td>NTFS root — every file ever created</td>\n          <td>Full file system timeline, timestamps, deleted files</td>\n          <td>MFTECmd, Autopsy</td>\n        </tr>\n        <tr>\n          <td><strong>LNK Files</strong></td>\n          <td><code>%APPDATA%\\Microsoft\\Windows\\Recent\\</code></td>\n          <td>Recently opened files — even if target deleted</td>\n          <td>LECmd</td>\n        </tr>\n        <tr>\n          <td><strong>Jump Lists</strong></td>\n          <td><code>%APPDATA%\\...\\AutomaticDestinations\\</code></td>\n          <td>Application usage history per app</td>\n          <td>JLECmd</td>\n        </tr>\n        <tr>\n          <td><strong>Browser History</strong></td>\n          <td>Chrome: <code>%APPDATA%\\...\\Chrome\\User Data\\Default\\History</code></td>\n          <td>Download URLs, C2 site visits, phishing page access</td>\n          <td>Hindsight, DB Browser</td>\n        </tr>\n        <tr>\n          <td><strong>USN Journal</strong></td>\n          <td>NTFS: <code>$Extend\\$UsnJrnl</code></td>\n          <td>File change log — see files created/deleted recently</td>\n          <td>MFTECmd</td>\n        </tr>\n        <tr>\n          <td><strong>SRUM</strong></td>\n          <td><code>C:\\Windows\\System32\\sru\\SRUDB.dat</code></td>\n          <td>30 days of network usage per app, process runtime</td>\n          <td>SrumECmd</td>\n        </tr>\n        <tr>\n          <td><strong>Registry Hives</strong></td>\n          <td><code>C:\\Windows\\System32\\config\\</code></td>\n          <td>SAM (hashes), SOFTWARE, SYSTEM, NTUSER.DAT</td>\n          <td>RegRipper, RECmd</td>\n        </tr>\n      </table>\n    </div>\n\n    <div class=\"card cl\">\n      <div class=\"clabel\">Evidence of Execution</div>\n      <div class=\"ctitle\" style=\"color:var(--lime2)\">ERIC ZIMMERMAN TOOLS — COLLECTION SCRIPT</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--lime2)\">\n<span class=\"lb\">POWERSHELL</span>\n<span class=\"C\"># Collect key forensic artifacts using EZ Tools (Eric Zimmerman)</span>\n<span class=\"C\"># Download: https://ericzimmermantools.com</span>\n\n<span class=\"K\">param</span>([string]<span class=\"V\">$OutDir</span> = <span class=\"S\">\"C:\\ForensicOutput\"</span>)\n<span class=\"F\">New-Item</span> -Path <span class=\"V\">$OutDir</span> -ItemType Directory -Force | <span class=\"F\">Out-Null</span>\n\n<span class=\"C\"># Prefetch — execution history</span>\n<span class=\"F\">.\\PECmd.exe</span> -d C:\\Windows\\Prefetch --csv <span class=\"V\">$OutDir</span>\\prefetch.csv\n\n<span class=\"C\"># AmCache — file execution with hashes</span>\n<span class=\"F\">.\\AmcacheParser.exe</span> -f <span class=\"S\">\"C:\\Windows\\AppCompat\\Programs\\Amcache.hve\"</span> `\n    --csv <span class=\"V\">$OutDir</span>\\amcache.csv\n\n<span class=\"C\"># Shimcache — even deleted executables</span>\n<span class=\"F\">.\\AppCompatCacheParser.exe</span> -f <span class=\"S\">\"C:\\Windows\\System32\\config\\SYSTEM\"</span> `\n    --csv <span class=\"V\">$OutDir</span>\\shimcache.csv\n\n<span class=\"C\"># MFT — complete file system timeline</span>\n<span class=\"F\">.\\MFTECmd.exe</span> -f <span class=\"S\">\"C:\\`$MFT\"</span> --csv <span class=\"V\">$OutDir</span>\\mft.csv\n\n<span class=\"C\"># Registry: Run keys, UserAssist, MRU lists</span>\n<span class=\"F\">.\\RECmd.exe</span> -d C:\\Windows\\System32\\config `\n    --bn .\\BatchExamples\\Kroll_Batch.reb `\n    --csv <span class=\"V\">$OutDir</span>\\registry.csv\n\n<span class=\"C\"># SRUM — 30-day network/process usage</span>\n<span class=\"F\">.\\SrumECmd.exe</span> -f <span class=\"S\">\"C:\\Windows\\System32\\sru\\SRUDB.dat\"</span> `\n    --csv <span class=\"V\">$OutDir</span>\\srum.csv\n\n<span class=\"F\">Write-Host</span> <span class=\"S\">\"[+] Artifacts collected to: $OutDir\"</span> -ForegroundColor Green</div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-timeline\">\n    <div class=\"card ca\" style=\"margin-bottom:14px\">\n      <div class=\"clabel\">Timeline Reconstruction</div>\n      <div class=\"ctitle\" style=\"color:var(--amber)\">SUPER TIMELINE WITH PLASO / LOG2TIMELINE</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--amber)\">\n<span class=\"lb\">BASH</span>\n<span class=\"C\"># Create a super timeline from a disk image or live system</span>\n<span class=\"C\"># Aggregates: MFT, event logs, prefetch, registry, browser history</span>\n\n<span class=\"C\"># Step 1: Create Plaso storage file from disk image</span>\n<span class=\"F\">log2timeline.py</span> --partitions all \\\n    /output/case001.plaso \\\n    /mnt/evidence/disk.raw\n\n<span class=\"C\"># Step 2: Filter and export to CSV timeline</span>\n<span class=\"F\">psort.py</span> -o l2tcsv \\\n    -w /output/timeline.csv \\\n    /output/case001.plaso \\\n    \"date &gt; '2025-01-01' AND date &lt; '2025-01-15'\"\n\n<span class=\"C\"># Step 3: Analyze with Timesketch (web UI) or grep</span>\n<span class=\"C\"># Find first execution of malware sample</span>\n<span class=\"F\">grep</span> -i \"malware_sample.exe\" timeline.csv | head -20\n\n<span class=\"C\"># Find all activity in 30min window around known IOC time</span>\n<span class=\"F\">awk</span> -F',' '$1 &gt;= \"2025-01-10T14:00\" && $1 &lt;= \"2025-01-10T14:30\"' \\\n    timeline.csv | <span class=\"F\">sort</span> -t',' -k1\n\n<span class=\"C\"># Timeline key fields: datetime | type | host | message</span>\n<span class=\"C\"># Correlate: file written → prefetch entry → network connection</span>\n<span class=\"C\"># That 3-event sequence confirms execution + C2</span></div>\n    </div>\n    <div class=\"card cl\">\n      <div class=\"clabel\">MACB Timestamps</div>\n      <div class=\"ctitle\" style=\"color:var(--lime2)\">TIMESTAMP ANALYSIS & TIMESTOMPING</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--lime2)\">\n<span class=\"C\"># MACB timestamps: Modified, Accessed, Created, $MFT Changed</span>\n<span class=\"C\"># Windows NTFS stores TWO sets: $STANDARD_INFO and $FILE_NAME</span>\n\n<span class=\"C\"># Normal file: all timestamps consistent between both attributes</span>\n<span class=\"C\"># Timestomped file: $STANDARD_INFO modified, $FILE_NAME unchanged</span>\n\n<span class=\"C\"># Detection of timestomping:</span>\n<span class=\"C\"># $STANDARD_INFO created date EARLIER than $FILE_NAME created date</span>\n<span class=\"C\"># → Impossible unless timestamps were backdated (timestomping)</span>\n\n<span class=\"C\"># Analyze with MFTECmd or Autopsy</span>\n<span class=\"F\">.\\MFTECmd.exe</span> -f C:\\<span class=\"V\">$MFT</span> --csv out\\ --vss\n<span class=\"C\"># Column: SI_Created vs FN_Created</span>\n<span class=\"C\"># If SI &lt; FN → timestomped → malware artifact</span>\n\n<span class=\"C\"># Linux equivalent: stat command shows all timestamps</span>\n<span class=\"F\">stat</span> /suspicious/binary\n<span class=\"C\"># File: /suspicious/binary</span>\n<span class=\"C\"># Access: 2025-01-10 14:23:11 ← matches system log entries</span>\n<span class=\"C\"># Modify: 2020-01-01 00:00:00 ← year 2020 is suspicious on 2025 system</span>\n<span class=\"C\"># Change: 2025-01-10 14:23:11 ← inode change = actual write time</span>\n<span class=\"C\"># Discrepancy between Modify and Change = timestomping</span></div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-linux-artifacts\">\n    <div class=\"card cl\" style=\"margin-bottom:14px\">\n      <div class=\"clabel\">Linux Forensic Artifacts</div>\n      <div class=\"ctitle\" style=\"color:var(--lime2)\">KEY ARTIFACT LOCATIONS</div>\n      <table class=\"dTable\">\n        <tr><th>ARTIFACT</th><th>PATH</th><th>INVESTIGATIVE VALUE</th></tr>\n        <tr><td><strong>Auth log</strong></td><td><code>/var/log/auth.log</code></td><td>SSH logons, sudo use, PAM events, brute force</td></tr>\n        <tr><td><strong>Syslog</strong></td><td><code>/var/log/syslog</code></td><td>General system events, cron execution, service starts</td></tr>\n        <tr><td><strong>Shell history</strong></td><td><code>~/.bash_history</code> <code>~/.zsh_history</code></td><td>Commands executed — often uncleared by attackers</td></tr>\n        <tr><td><strong>Crontabs</strong></td><td><code>/var/spool/cron/crontabs/</code> <code>/etc/cron.d/</code></td><td>Persistence via scheduled jobs</td></tr>\n        <tr><td><strong>Systemd units</strong></td><td><code>/etc/systemd/system/</code></td><td>Malicious service persistence</td></tr>\n        <tr><td><strong>ld.so.preload</strong></td><td><code>/etc/ld.so.preload</code></td><td>Should be EMPTY — rootkit injection if not</td></tr>\n        <tr><td><strong>SSH keys</strong></td><td><code>~/.ssh/authorized_keys</code></td><td>Backdoor keys added by attacker</td></tr>\n        <tr><td><strong>/tmp & /var/tmp</strong></td><td>World-writable directories</td><td>Common malware staging area</td></tr>\n        <tr><td><strong>wtmp / lastlog</strong></td><td><code>/var/log/wtmp</code></td><td>Login history — use <code>last</code> command</td></tr>\n        <tr><td><strong>Kernel modules</strong></td><td><code>/lib/modules/</code></td><td>Rootkit LKMs — compare <code>lsmod</code> vs disk</td></tr>\n        <tr><td><strong>Deleted files</strong></td><td>Via <code>lsof +L1</code></td><td>Files open but deleted — malware hiding itself</td></tr>\n      </table>\n    </div>\n    <div class=\"card cc\">\n      <div class=\"clabel\">Deleted File Recovery</div>\n      <div class=\"ctitle\" style=\"color:var(--cyan2)\">RECOVER MALWARE FROM DELETED FILES</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"lb\">BASH</span>\n<span class=\"C\"># Malware often deletes itself after execution</span>\n<span class=\"C\"># But if a process still has the file open, it's recoverable via /proc</span>\n\n<span class=\"C\"># Find processes with deleted files open</span>\n<span class=\"F\">lsof</span> +L1 | <span class=\"F\">grep</span> deleted\n<span class=\"C\"># Output example:</span>\n<span class=\"C\"># evil_proc 1337 root 5r REG 8,1 0 1337 /tmp/.hidden (deleted)</span>\n\n<span class=\"C\"># Recover from /proc filesystem</span>\n<span class=\"C\"># PID 1337, file descriptor 5</span>\n<span class=\"F\">cp</span> /proc/1337/fd/5 /evidence/recovered_malware\n<span class=\"F\">sha256sum</span> /evidence/recovered_malware\n<span class=\"C\"># Now you have the binary even though it was \"deleted\"</span>\n\n<span class=\"C\"># Recover file content from ext4 via debugfs</span>\n<span class=\"F\">debugfs</span> /dev/sda1\n<span class=\"C\"># debugfs commands:</span>\n<span class=\"H\">  lsdel</span>               <span class=\"C\"># list deleted inodes</span>\n<span class=\"H\">  undel &lt;inode&gt; /output/file</span>  <span class=\"C\"># recover if still allocated</span>\n\n<span class=\"C\"># Recover via strings on raw disk image (last resort)</span>\n<span class=\"F\">strings</span> /dev/sda1 | <span class=\"F\">grep</span> -A 20 <span class=\"S\">\"ELF\"</span>\n<span class=\"F\">foremost</span> -i disk.raw -t exe,elf -o /recovered/  <span class=\"C\"># file carving</span></div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: IR PLAYBOOKS\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-playbooks\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.6 — Incident Response //</div>\n      <div class=\"sh-title\">IR Playbooks</div>\n      <div class=\"sh-desc\">Structured response procedures for the most common incident types. Each playbook defines decision gates, evidence preservation steps, containment actions, and escalation paths.</div>\n    </div>\n  </div>\n\n  <div class=\"itabs\">\n    <button class=\"itab active\" onclick=\"iTab('pb-ransom',this)\">Ransomware</button>\n    <button class=\"itab\" onclick=\"iTab('pb-apt',this)\">APT / Breach</button>\n    <button class=\"itab\" onclick=\"iTab('pb-phish',this)\">Phishing</button>\n  </div>\n\n  <div class=\"ipanel active\" id=\"ip-pb-ransom\">\n    <div class=\"alert a-err\"><strong>RANSOMWARE INCIDENT:</strong> Do NOT reboot affected systems. Do NOT attempt to decrypt. Preserve evidence before any remediation. Notify legal/counsel before any external communication.</div>\n    <div class=\"g2\" style=\"margin-bottom:14px\">\n      <div class=\"card cr\">\n        <div class=\"clabel\">Phase 1 — First 30 Minutes</div>\n        <div class=\"ctitle\" style=\"color:var(--red)\">DETECT & CONTAIN</div>\n        <div class=\"codeblock\" style=\"--cb-accent:var(--red)\">\n<span class=\"R\">IMMEDIATE ACTIONS (first 15 min)</span>\n\n<span class=\"N\">1.</span> ISOLATE affected hosts\n   → Network isolation (firewall rule or physical disconnect)\n   → Do NOT power off (memory evidence!)\n   → Keep VPN/RDP for responder access\n\n<span class=\"N\">2.</span> ASSESS blast radius\n   → How many hosts show encrypted files?\n   → Any domain controllers affected?\n   → Any backups accessible from network?\n\n<span class=\"N\">3.</span> STOP the spread\n   → Block C2 domains/IPs at perimeter\n   → Disable affected user accounts\n   → Kill malicious processes if still running:\n     taskkill /PID &lt;pid&gt; /F\n     pkill -f malware_name\n\n<span class=\"N\">4.</span> PRESERVE evidence\n   → Run IR collection script (Module 01)\n   → Take memory dump (winpmem)\n   → Screenshot ransom note + wallpaper\n   → Log everything with timestamps</div>\n      </div>\n      <div class=\"card cr\">\n        <div class=\"clabel\">Phase 2 — First 4 Hours</div>\n        <div class=\"ctitle\" style=\"color:var(--red)\">INVESTIGATE</div>\n        <div class=\"codeblock\" style=\"--cb-accent:var(--red)\">\n<span class=\"R\">INVESTIGATION PRIORITIES</span>\n\n<span class=\"N\">1.</span> IDENTIFY PATIENT ZERO\n   → First system with encrypted files (MFT timestamps)\n   → First NXDOMAIN burst (DNS logs)\n   → First unusual process execution (Sysmon Ev1)\n\n<span class=\"N\">2.</span> ESTABLISH TIMELINE\n   → Delivery (phishing email timestamp)\n   → Execution (first malware process)\n   → Lateral movement (logon events 4624 to other hosts)\n   → Encryption start (mass FileCreate events)\n\n<span class=\"N\">3.</span> DETERMINE PERSISTENCE\n   → Check all Run keys on all hosts\n   → Check scheduled tasks\n   → Check services\n   → Check WMI subscriptions\n\n<span class=\"N\">4.</span> COLLECT IOCs\n   → Malware hashes\n   → C2 IPs and domains\n   → Ransom note filename pattern\n   → Encrypted file extension (.locked etc.)\n   → Mutex name (from memory forensics)</div>\n      </div>\n    </div>\n    <div class=\"card ca\">\n      <div class=\"clabel\">Decision Tree</div>\n      <div class=\"ctitle\" style=\"color:var(--amber)\">TO PAY OR NOT TO PAY — DECISION FRAMEWORK</div>\n      <div class=\"codeblock\" style=\"--cb-accent:var(--amber)\">\n<span class=\"Y\">ASSESSMENT QUESTIONS (answer before any payment decision):</span>\n\n<span class=\"N\">1.</span> Do we have working backups? (offline, tested, recent)\n    YES → Restore from backup. No payment needed.\n    NO  → Continue assessment\n\n<span class=\"N\">2.</span> Is there a free decryptor available?\n    Check: https://www.nomoreransom.org\n    YES → Use it. No payment needed.\n    NO  → Continue\n\n<span class=\"N\">3.</span> Was data exfiltrated before encryption? (double extortion)\n    → Check network logs for large outbound transfers\n    → Check threat actor's leak site\n\n<span class=\"N\">4.</span> What is the business impact of non-recovery?\n    → Calculate downtime cost vs ransom amount\n    → Involve legal, executive, cyber insurer\n\n<span class=\"Y\">LEGAL CONSIDERATIONS:</span>\n   → Paying may violate OFAC sanctions if attacker is sanctioned group\n   → Check: https://home.treasury.gov/policy-issues/financial-sanctions\n   → Consult legal counsel before any payment\n\n<span class=\"G\">TECHNICAL NOTE:</span>\n   → Payment does NOT guarantee decryption\n   → Ransomware-as-a-Service operators have poor customer service\n   → Decryptors often corrupt files or fail on large sets</div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-pb-apt\">\n    <div class=\"alert a-warn\"><strong>APT / BREACH:</strong> Assume the attacker is watching. Do NOT alert them via noisy containment. Build a parallel clean environment for communication. The goal is understand the full scope before eviction.</div>\n    <div class=\"g2\" style=\"margin-bottom:14px\">\n      <div class=\"card ca\">\n        <div class=\"clabel\">APT Response — Phase 1</div>\n        <div class=\"ctitle\" style=\"color:var(--amber)\">SCOPING & SILENT INVESTIGATION</div>\n        <div class=\"codeblock\" style=\"--cb-accent:var(--amber)\">\n<span class=\"Y\">OBJECTIVE: Understand scope without tipping off attacker</span>\n\n<span class=\"N\">1.</span> ESTABLISH SECURE COMMS\n   → Out-of-band communication (personal phones, Signal)\n   → Do NOT use compromised email/Slack for IR\n   → Create fresh accounts in cloud tenant if needed\n\n<span class=\"N\">2.</span> PASSIVE HUNTING (no action yet)\n   → Query SIEM for IOCs across ALL hosts (not just known ones)\n   → Map all C2 beaconing from DNS/proxy logs\n   → Identify ALL compromised accounts (logon from C2 IP)\n   → Do NOT touch malware yet — attacker may have tripwires\n\n<span class=\"N\">3.</span> IDENTIFY ATTACKER OBJECTIVES\n   → What data did they access? (file access logs, DLP)\n   → Where did they pivot to? (lateral movement map)\n   → Do they have persistence on critical systems?\n   → Have they reached AD / domain controllers?\n\n<span class=\"N\">4.</span> DOCUMENT EVERYTHING\n   → Full network diagram of attacker's path\n   → Timeline from first compromise to discovery\n   → All tools/techniques used (ATT&CK mapping)</div>\n      </div>\n      <div class=\"card ca\">\n        <div class=\"clabel\">APT Response — Phase 2</div>\n        <div class=\"ctitle\" style=\"color:var(--amber)\">COORDINATED EVICTION</div>\n        <div class=\"codeblock\" style=\"--cb-accent:var(--amber)\">\n<span class=\"Y\">EVICTION: Do it all at once. Give attacker no time to react.</span>\n\n<span class=\"N\">1.</span> PRE-EVICTION CHECKLIST\n   → All persistence mechanisms identified and documented\n   → New credentials prepared for ALL privileged accounts\n   → New domain admin accounts pre-created (offline)\n   → Legal/law enforcement notified if required\n   → Backup integrity verified (offline, isolated)\n\n<span class=\"N\">2.</span> SIMULTANEOUS EVICTION (T=0)\n   → Block all C2 at perimeter (all identified IPs/domains)\n   → Force password reset ALL domain accounts\n   → Revoke ALL Kerberos tickets: klist purge\n   → Rotate ALL service account credentials\n   → Remove ALL persistence (run keys, tasks, services)\n   → Reinstall compromised hosts from known-good image\n\n<span class=\"N\">3.</span> KRBTGT KEY ROTATION (if DC compromised)\n   → Reset KRBTGT password TWICE (defeats golden tickets)\n   → Interval: 10 hours between resets (Kerberos ticket lifetime)\n   → This invalidates all existing Kerberos tickets\n\n<span class=\"N\">4.</span> POST-EVICTION MONITORING\n   → 30-day elevated monitoring for reinfection attempts\n   → Watch for attacker returning via new vector</div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-pb-phish\">\n    <div class=\"g2\">\n      <div class=\"card cl\">\n        <div class=\"clabel\">Phishing Response</div>\n        <div class=\"ctitle\" style=\"color:var(--lime2)\">EMAIL INCIDENT PLAYBOOK</div>\n        <div class=\"codeblock\" style=\"--cb-accent:var(--lime2)\">\n<span class=\"G\">PHISHING TRIAGE WORKFLOW</span>\n\n<span class=\"N\">1.</span> COLLECT EVIDENCE\n   → Get original email with full headers\n   → Download attachment to isolated sandbox\n   → Extract URLs from email body\n   → Do NOT click links from primary workstation\n\n<span class=\"N\">2.</span> ANALYZE EMAIL HEADERS\n   Received: headers (trace path)\n   Return-Path: vs From: mismatch → spoofing\n   DKIM-Signature: pass/fail\n   SPF: pass/fail/softfail\n   DMARC: pass/fail/none\n\n<span class=\"N\">3.</span> SANDBOX ATTACHMENT/URL\n   Any.run, Hybrid Analysis, or local Cuckoo\n   → Capture: dropped files, network C2, registry\n\n<span class=\"N\">4.</span> ASSESS USER IMPACT\n   → Did user click? (email gateway click tracking)\n   → Did user enter credentials? (check auth logs)\n   → Did malware execute? (EDR alert, Sysmon events)\n\n<span class=\"N\">5.</span> HUNT FOR OTHER RECIPIENTS\n   PowerShell / Microsoft Graph API:\n   Search-UnifiedAuditLog -RecordType ExchangeItem\n   -Operations \"Send\" — find all sent copies</div>\n      </div>\n      <div class=\"card cl\">\n        <div class=\"clabel\">Phishing — Remediation</div>\n        <div class=\"ctitle\" style=\"color:var(--lime2)\">CONTAINMENT & RECOVERY</div>\n        <div class=\"codeblock\" style=\"--cb-accent:var(--lime2)\">\n<span class=\"G\">REMEDIATION STEPS</span>\n\n<span class=\"N\">1.</span> PURGE EMAIL FROM ALL MAILBOXES\n   PowerShell (Exchange Online):\n   <span class=\"F\">Search-Mailbox</span> -SearchQuery <span class=\"S\">\"subject:'Urgent Invoice'\"</span> `\n       -DeleteContent -Force\n   <span class=\"C\"># Or: Compliance Center → Content Search → Purge</span>\n\n<span class=\"N\">2.</span> BLOCK SENDER/DOMAIN\n   → Add to Exchange blocked senders\n   → Submit URL to Microsoft/Google Safe Browsing\n   → Block domain at DNS/proxy layer\n\n<span class=\"N\">3.</span> IF USER CLICKED/ENTERED CREDS:\n   → Force password reset immediately\n   → Revoke all active sessions (invalidate tokens)\n   → Enable MFA if not already enabled\n   → Check for mail forwarding rules (attacker persistence)\n   → Audit inbox rules: New-InboxRule backdoor common\n\n<span class=\"N\">4.</span> IF MALWARE EXECUTED:\n   → Escalate to full IR playbook\n   → Isolate the endpoint\n   → Preserve memory image\n   → Follow endpoint IR procedure\n\n<span class=\"N\">5.</span> USER COMMUNICATION\n   → Notify user (without blame)\n   → Reinforce reporting culture\n   → Brief department heads if sensitive data at risk</div>\n      </div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     TAB: QUIZ\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-quiz\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-accent\"></div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// 4.7 — Competency Verification //</div>\n      <div class=\"sh-title\">Knowledge Check</div>\n      <div class=\"sh-desc\">Ten scenario-based questions covering detection methodology, EDR, Sigma authoring, SIEM queries, threat hunting, forensics, and IR playbooks.</div>\n    </div>\n  </div>\n\n  <div id=\"quiz-container\"></div>\n\n  <div class=\"score-box\">\n    <div style=\"font-family:var(--mono);font-size:.55rem;letter-spacing:2px;color:var(--dim);margin-bottom:6px\">SCORE</div>\n    <div id=\"score-text\" style=\"font-family:var(--mono);font-size:.8rem;color:var(--amber)\"></div>\n    <div class=\"score-track\"><div class=\"score-fill\" id=\"score-fill\" style=\"width:0%\"></div></div>\n    <button class=\"reset-btn\" onclick=\"resetQuiz()\">RESET QUIZ</button>\n  </div>\n\n</div>\n</div>\n\n<script>\n// ── Tab switching ──────────────────────────────────\nfunction sw(id, btn) {\n  document.querySelectorAll('.module').forEach(m => m.classList.remove('active'));\n  document.querySelectorAll('.ntab').forEach(t => t.classList.remove('active'));\n  document.getElementById('mod-' + id).classList.add('active');\n  btn.classList.add('active');\n  window.scrollTo({ top: 0, behavior: 'smooth' });\n}\n\nfunction iTab(id, btn) {\n  const mod = btn.closest('.module');\n  mod.querySelectorAll('.itab').forEach(t => t.classList.remove('active'));\n  mod.querySelectorAll('.ipanel').forEach(p => p.classList.remove('active'));\n  btn.classList.add('active');\n  document.getElementById('ip-' + id).classList.add('active');\n}\n\n// ── Quiz ──────────────────────────────────────────\nconst questions = [\n  {\n    q: \"The Pyramid of Pain concept suggests that blocking file hashes is a low-value detection strategy. Why, and what approach should you prioritize instead?\",\n    opts: [\n      \"Hash blocking is computationally expensive — prioritize IP blocking for efficiency\",\n      \"Attackers trivially recompile or pad binaries to change hashes, making hash blocks useless within minutes. Prioritize TTP-level behavioral detections — detecting how malware acts is much harder for attackers to change than what a specific binary looks like\",\n      \"Hash blocking is actually the most effective — always use it as the primary detection layer\",\n      \"Hash blocking should be replaced by domain blocking, which is more resilient\"\n    ],\n    correct: 1,\n    explain: \"<strong>Pyramid of Pain — higher = more attacker pain.</strong> File hashes sit at the bottom — a single bit change (add a null byte, recompile) creates a completely new hash. An attacker can do this in 30 seconds. TTP-level detections (behaviors like 'Office process spawning PowerShell with encoded command') require the attacker to fundamentally change their tooling and methodology — far more expensive. The ideal detection stack combines: hash/IP blocks (fast, cheap, low-friction) at the bottom, with behavioral Sigma/YARA/ML rules targeting TTPs at the top. The top of the pyramid should be your investment focus.\"\n  },\n  {\n    q: \"Your Sigma rule fires with a very high false positive rate. Analysts are ignoring it. What is the most effective first step to fix it?\",\n    opts: [\n      \"Lower the severity level from HIGH to LOW so analysts know to deprioritize it\",\n      \"Delete the rule and write a new one from scratch\",\n      \"Add a filter_legit block that excludes known-good processes/paths. Then analyze the remaining true positives to tighten the selection logic\",\n      \"Change the logsource to a different log category to reduce data volume\"\n    ],\n    correct: 2,\n    explain: \"<strong>Sigma rule tuning — the filter approach.</strong> High false positive rates kill analyst trust and cause alert fatigue. The correct approach: (1) Collect a week of FP data — which processes/paths generate false alerts? (2) Add a <code>filter_legit</code> block excluding those specific patterns with AND NOT in the condition. (3) If FP rate is still high after filtering, tighten the selection logic — require more conditions to be true simultaneously (more AND clauses). Never lower severity to hide the problem — that just ensures true positives are also missed. A good rule should have <5% FP rate in production.\"\n  },\n  {\n    q: \"During threat hunting, you query DNS logs and find a host making 847 DNS queries in one hour, with 92% returning NXDOMAIN, to domains like 'k3mq9xzt4pw2.com', 'n8vb2cjhm6xr.com'. What is this, and what is the immediate action?\",\n    opts: [\n      \"Normal browser behavior — modern web pages make hundreds of DNS queries\",\n      \"DGA botnet activity — the host is infected and cycling through generated C2 domains. Immediately isolate the host, preserve memory, extract the malware, and identify the DGA algorithm to sinkhole future domains\",\n      \"DNS cache poisoning attack against the host — flush DNS cache and update resolver\",\n      \"Antivirus performing domain reputation lookups — whitelist the process\"\n    ],\n    correct: 1,\n    explain: \"<strong>DGA (Domain Generation Algorithm) botnet confirmed.</strong> Three definitive signals: (1) 92% NXDOMAIN rate — the bot cycles through generated domains, most don't exist (attacker only registers 1-2), (2) High-entropy, short random-looking domain names — not human-typed, algorithmically generated, (3) Volume — 847 queries/hour is far above any legitimate software. Immediate actions: isolate host (prevent actual C2 if attacker registers a new domain), preserve memory (Volatility to extract malware and DGA seed), analyze the malware to identify the DGA family (Conficker, GameOver Zeus etc.), pre-generate future domains and sinkhole them to map all infected hosts.\"\n  },\n  {\n    q: \"A Sigma rule uses `condition: selection and not filter_legit`. What happens if filter_legit matches but selection does NOT?\",\n    opts: [\n      \"The rule fires — because NOT filter_legit is TRUE\",\n      \"The rule does NOT fire — selection must be TRUE first. If selection is false, the condition short-circuits regardless of filter_legit\",\n      \"It depends on the SIEM backend conversion\",\n      \"The rule throws a syntax error — conditions cannot combine AND and NOT\"\n    ],\n    correct: 1,\n    explain: \"<strong>Boolean short-circuit evaluation in Sigma conditions.</strong> The condition <code>selection AND NOT filter_legit</code> requires BOTH: (1) selection must be TRUE, AND (2) filter_legit must be FALSE. If selection is FALSE, the entire condition is FALSE regardless of filter_legit — because FALSE AND anything = FALSE. This matters operationally: filter blocks only apply when the selection has already matched. This is intentional — filters are only relevant when the selection fires. If you want 'fire unless certain processes regardless of selection', use a different rule structure: <code>selection AND NOT (filter_legit)</code> vs <code>NOT filter_legit AND selection</code> — same Boolean result but clarity matters for reviewers.\"\n  },\n  {\n    q: \"During forensic analysis, you notice a file's $STANDARD_INFORMATION Created timestamp is January 2020, but its $FILE_NAME Created timestamp is January 2025. The system was built in 2024. What does this indicate?\",\n    opts: [\n      \"The file was legitimately created in 2020 and the system was rebuilt around it\",\n      \"Timestomping — the attacker backdated the $STANDARD_INFORMATION timestamps to make the malware appear old. $FILE_NAME timestamps are harder to modify and reveal the true creation time (2025)\",\n      \"NTFS timestamp corruption — run chkdsk to repair\",\n      \"The file was copied from an old backup — normal behavior for patch management\"\n    ],\n    correct: 1,\n    explain: \"<strong>Timestomping detected via NTFS dual-timestamp analysis.</strong> Windows NTFS stores two sets of timestamps per file: $STANDARD_INFORMATION (shown by dir/Explorer — easily modified via SetFileTime API) and $FILE_NAME (stored in the directory entry — much harder to modify, requires kernel-level access). When $SI_Created < $FN_Created, it's impossible naturally — the file record can't precede the file name entry. This discrepancy definitively indicates timestomping (T1070.006). Tool: MFTECmd with the --csv flag — compare SI_Created vs FN_Created columns. The $FN timestamp reveals the actual file drop time: January 2025.\"\n  },\n  {\n    q: \"You're writing a KQL query to detect C2 beaconing. You measure 'stdev of connection timestamps' and filter for < 5.0. Why is low standard deviation significant?\",\n    opts: [\n      \"Low standard deviation means few connections — fewer than 5 total, indicating low volume C2\",\n      \"Low standard deviation means the connection intervals are highly regular/periodic — malware beacons on a fixed schedule (with jitter). Legitimate software does not communicate with external hosts on perfectly regular intervals\",\n      \"Low standard deviation means the connection is encrypted — TLS handshakes are shorter\",\n      \"Low standard deviation filters out high-volume noise from browsers — only keeps idle connections\"\n    ],\n    correct: 1,\n    explain: \"<strong>Statistical periodicity analysis for beacon detection.</strong> Standard deviation measures how much values vary from the mean. In connection timing: Low stddev = highly regular intervals (e.g., exactly 60s ± 2s). This is the mathematical signature of a beacon. Human-driven or legitimate software traffic is bursty and irregular (high stddev). Even C2 with jitter (e.g., ±20%) still has lower stddev than legitimate browsing. The KQL approach: bin timestamps, measure stdev per source-destination pair over 24h, filter stdev < threshold AND count > minimum. This catches beacons that evade simple 'periodic query' detection by using jitter. Key tuning parameter: stdev threshold depends on jitter amount — more jitter = higher threshold needed.\"\n  },\n  {\n    q: \"During APT response, a colleague wants to immediately isolate all affected hosts and reset all passwords at hour 2 of the investigation. What is the correct recommendation?\",\n    opts: [\n      \"Agree — speed is critical, isolate immediately before the attacker causes more damage\",\n      \"Disagree — premature eviction alerts the attacker. Spend time understanding the full scope (all compromised hosts, all C2 channels, all persistence) before coordinated simultaneous eviction. Partial eviction gives the attacker time to activate backup persistence or destroy evidence\",\n      \"Disagree — you should notify law enforcement first, then isolate after 5 business days\",\n      \"Agree, but only reset passwords — don't isolate hosts yet\"\n    ],\n    correct: 1,\n    explain: \"<strong>Coordinated eviction — not piecemeal.</strong> Premature partial eviction is one of the most common IR mistakes in APT cases. If you isolate 3 hosts at hour 2, the attacker (who may be actively watching C2 dashboards) immediately knows detection has occurred and can: activate backup persistence mechanisms, destroy evidence (logs, artifacts), move laterally to unchecked systems, accelerate their mission (exfil, destroy). The correct approach: scope fully (all compromised hosts, all C2, all persistence, all stolen credentials), then evict everything simultaneously at a planned T=0. For ransomware (already destructive) or active exfil, the calculus changes — earlier containment may be warranted.\"\n  },\n  {\n    q: \"Your Sigma rule targets Sysmon Event ID 8 (CreateRemoteThread). A junior analyst asks: 'Can't attackers just avoid using CreateRemoteThread?'. What is the correct technical response?\",\n    opts: [\n      \"No — Windows requires CreateRemoteThread for all cross-process code execution\",\n      \"Yes — attackers can use alternative injection techniques (APC injection, thread hijacking, SetThreadContext, NtCreateThreadEx) that don't generate Event ID 8. This is why you need multiple overlapping rules targeting each injection technique, PLUS memory-scanning rules that catch the result rather than the mechanism\",\n      \"No — Sysmon captures all injection attempts regardless of API used\",\n      \"Yes — but only on Windows 7. Modern Windows requires CreateRemoteThread\"\n    ],\n    correct: 1,\n    explain: \"<strong>Detection in depth — multiple injection rules required.</strong> CreateRemoteThread (Sysmon Ev8) is one injection method, but attackers have many alternatives: APC Injection (NtQueueApcThread — no Ev8), Thread Hijacking (SuspendThread → GetThreadContext → SetThreadContext → ResumeThread — no Ev8), Module Stomping (overwrite DLL in place — no Ev8), Reflective DLL (no Windows API at all — only ETW/memory scanning detects it). Defense-in-depth requires: Ev8 rule + Ev10 (process access) rule + malfind-style memory scanning + behavioral rules (processes making unexpected network connections). No single rule catches all injection. Attackers will always move to the path your rules don't cover — your detection portfolio must be deep.\"\n  },\n  {\n    q: \"During a ransomware incident, you find the malware deleted itself after encryption but a suspicious process is still running. How do you recover the binary?\",\n    opts: [\n      \"You cannot — once deleted, the file is permanently unrecoverable\",\n      \"Check /proc/<PID>/fd/ on Linux or use Task Manager's 'Create dump file' — the process still holds a file descriptor to the deleted binary, which remains on disk until all handles are closed\",\n      \"Run file carving (foremost/photorec) on the entire disk — will take several hours\",\n      \"Restore from the most recent backup of the malware's directory\"\n    ],\n    correct: 1,\n    explain: \"<strong>Process file descriptor recovery from /proc.</strong> On Linux, when a process opens a file, the kernel keeps the file's inode alive as long as any process has an open file descriptor to it — even if the filename is deleted from the directory. The file lives at <code>/proc/&lt;PID&gt;/fd/&lt;FD&gt;</code>. Steps: (1) <code>lsof +L1</code> — lists open files with link count 0 (deleted), (2) Find the PID and FD number, (3) <code>cp /proc/1337/fd/5 /evidence/recovered_binary</code>. On Windows, the equivalent is creating a process dump via Task Manager or ProcDump, then analyzing the dump for embedded PE headers. This technique is why malware authors can't rely solely on self-deletion — the running process betrays the binary until it terminates.\"\n  },\n  {\n    q: \"You need to write a detection for ransomware's VSS shadow copy deletion. The attacker uses three different commands: 'vssadmin delete shadows', 'wmic shadowcopy delete', and 'wbadmin delete catalog'. What is the best Sigma condition structure?\",\n    opts: [\n      \"condition: sel_vssadmin and sel_wmic and sel_wbadmin (all three must match)\",\n      \"condition: sel_vssadmin or sel_wmic or sel_wbadmin (any one match triggers)\",\n      \"condition: 2 of (sel_vssadmin, sel_wmic, sel_wbadmin) (at least two must match)\",\n      \"condition: not (sel_vssadmin or sel_wmic or sel_wbadmin) (fire when none match)\"\n    ],\n    correct: 1,\n    explain: \"<strong>OR condition for equivalent techniques — any is malicious.</strong> Each of the three commands (vssadmin, wmic shadowcopy, wbadmin) independently performs the same malicious action: deleting backup snapshots. An attacker uses only ONE of them — requiring ALL three (AND) would almost never fire. Requiring exactly 2-of-3 misses cases where the attacker uses only one technique. The correct structure is OR — ANY single occurrence is already critical. This is a pattern for when: multiple techniques achieve the same malicious goal, each technique is independently malicious (not a false positive individually), the attacker chooses one path. Contrast with process injection detection where you might require multiple APIs together (AND) because each API alone has legitimate uses.\"\n  }\n];\n\nlet answered = new Array(questions.length).fill(false);\nlet correct_count = 0;\n\nfunction buildQuiz() {\n  const c = document.getElementById('quiz-container');\n  c.innerHTML = '';\n  questions.forEach((q, qi) => {\n    const div = document.createElement('div');\n    div.className = 'quiz-card';\n    div.innerHTML = `\n      <div class=\"qnum\">Q${String(qi+1).padStart(2,'0')} / ${questions.length} — ${['Detection Methodology','Sigma Tuning','Threat Hunting','Sigma Logic','Forensics','Beaconing','APT Response','EDR Coverage','Recovery','Rule Design'][qi]}</div>\n      <div class=\"qtext\">${q.q}</div>\n      <div class=\"qopts\">${q.opts.map((o,oi) => `<button class=\"qopt\" onclick=\"answer(${qi},${oi},this)\">${String.fromCharCode(65+oi)}. ${o}</button>`).join('')}</div>\n      <div class=\"qexplain\" id=\"exp-${qi}\">${q.explain}</div>\n    `;\n    c.appendChild(div);\n  });\n  updateScore();\n}\n\nfunction answer(qi, oi, btn) {\n  if (answered[qi]) return;\n  answered[qi] = true;\n  const q = questions[qi];\n  btn.closest('.qopts').querySelectorAll('.qopt').forEach(b => b.classList.add('locked'));\n  if (oi === q.correct) { btn.classList.add('correct'); correct_count++; }\n  else { btn.classList.add('wrong'); btn.closest('.qopts').querySelectorAll('.qopt')[q.correct].classList.add('correct'); }\n  document.getElementById('exp-' + qi).classList.add('show');\n  updateScore();\n}\n\nfunction updateScore() {\n  const done = answered.filter(Boolean).length;\n  if (done === 0) { document.getElementById('score-text').textContent = 'Answer questions to track your score'; return; }\n  const pct = Math.round(correct_count / done * 100);\n  document.getElementById('score-text').textContent = `${correct_count}/${done} correct — ${pct}% — ${questions.length - done} remaining`;\n  const fill = document.getElementById('score-fill');\n  fill.style.width = pct + '%';\n  fill.style.background = pct >= 80 ? '#7dff4f' : pct >= 60 ? '#ffb700' : '#ff3322';\n}\n\nfunction resetQuiz() {\n  answered = new Array(questions.length).fill(false);\n  correct_count = 0;\n  buildQuiz();\n}\n\nbuildQuiz();\n</script>\n</body>\n</html>\n";

export default detectionEngineeringDefenseHtml;
